INSERT INTO "public"."acoes_estrategicas" ("id", "numero", "nome", "eixo_prioritario_id", "objetivo_estrategico_id", "estrategia_id", "acoes_conectadas", "descricao_oficial_completa", "descricao_o_que", "descricao_para_que", "ancoragem", "nota_arranjo_institucional", "versao", "data_elaboracao", "elaboracao", "proxima_fase", "created_at", "updated_at") VALUES
	(1, '10.1.2', 'Desenvolver portfólio de projetos comunitários em PDC para adesão municipal', 1, 2, 2, 'AE 10.1.1 (Material audiovisual de percepção de risco) | AE 10.1.3 (Orientação técnica aos municípios) | AE 8.1.5 (Colaboração em prevenção/mitigação)', 'Modelagem de soluções, materiais de apoio e metodologias de proteção comunitária replicáveis (O QUÊ), visando fomentar e facilitar a implementação de políticas locais de percepção de risco de desastres nos municípios integrantes do SIEPDEC-RJ. (PARA QUÊ).', 'Modelagem de soluções, materiais de apoio e metodologias de proteção comunitária replicáveis.', 'Fomentar e facilitar a implementação de políticas locais de percepção de risco de desastres nos municípios integrantes do SIEPDEC-RJ.', 'A percepção de risco e a conscientização comunitária são competências municipais que dependem de capacidade técnica local. Muitos municípios não dispõem de metodologias, modelos ou referências para implementar projetos de proteção comunitária. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E10.1, com foco na modelagem de soluções, materiais de apoio e metodologias de proteção comunitária replicáveis. As iniciativas indicadas são colher melhores práticas de projetos com os municípios e disponibilizar o portfólio para adesão.', NULL, '1.0', '2026-02-18', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(2, '1.1.3', 'Buscar novas fontes de recursos e criar receitas', 2, 1, 1, 'AE 1.1.1 (Otimizar estrutura orçamentária) | AE 1.1.2 (Redimensionar orçamento) | AE 1.1.4 (Potencializar receitas existentes) | AE 2.1.2 (Gestão de projetos) | AE 2.1.3 (Instrumentos institucionais) | AE 7.1.2 (Atuação parlamentar)', 'Estruturação para prospecção de editais, operacionalização e otimização de fundo estadual de defesa civil, aproveitamento de fundos nacionais/estaduais/internacionais e parcerias público-privadas (O QUÊ), visando diversificar a matriz de financiamento da Defesa Civil e reduzir a dependência exclusiva do tesouro estadual para investimentos (PARA QUÊ).', 'Estruturação para prospecção de editais, operacionalização e otimização de fundo estadual de defesa civil, aproveitamento de fundos nacionais/estaduais/internacionais e parcerias público-privadas.', 'Diversificar a matriz de financiamento da Defesa Civil e reduzir a dependência exclusiva do tesouro estadual para investimentos.', 'Esta ação encontra fundamento na Lei Federal nº 12.608/2012, que institui a Política Nacional de Proteção e Defesa Civil e prevê a articulação entre os entes federados para captação e aplicação de recursos. No âmbito estadual, a PEPDEC (Decreto nº 46.935/2020) estabelece, em seu Art. 4º, inciso XVII, o objetivo de “estimular o investimento econômico que viabilize políticas públicas integradas à proteção e defesa civil”. O Plano Estratégico 2024–2035 posiciona esta ação dentro da Estratégia E1.1, cuja premissa é que a Secretaria não pode depender exclusivamente do Tesouro Estadual para financiar seus investimentos.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(3, '2.1.1', 'Institucionalizar a gestão estratégica', 3, 3, 3, 'AE 2.1.2 (Gestão de projetos) | AE 2.1.3 (Instrumentos institucionais) | AE 2.1.4 (Cultura organizacional) | AE 2.1.6 (Gestão de processos) | AE 2.1.7 (Gestão por competências) | AE 2.1.8 (Diagnóstico do SIEPDEC)', 'Implementação de rotinas de monitoramento de desempenho e análise crítica de indicadores (O QUÊ), visando assegurar o alinhamento contínuo da execução orçamentária e operacional às diretrizes de longo prazo estabelecidas no Plano Estratégico (PARA QUÊ).', 'Implementação de rotinas de monitoramento de desempenho e análise crítica de indicadores.', 'Assegurar o alinhamento contínuo da execução orçamentária e operacional às diretrizes de longo prazo estabelecidas no Plano Estratégico.', 'A institucionalização da gestão estratégica constitui o alicerce sobre o qual todas as demais ações do Plano Estratégico 2024–2035 se sustentam. A Lei Federal nº 12.608/2012 fundamenta a necessidade de planejamento contínuo em proteção e defesa civil. A PEPDEC (Decreto nº 46.935/2020) reforça, em seu Art. 3º, inciso IV, o princípio do “planejamento com base em pesquisas e estudos sobre riscos de desastres”. O próprio Plano Estratégico atribui explicitamente à Divisão de Análise Estratégica e Apoio à Decisão (DAEAD) do ICTDEC a responsabilidade pelo monitoramento global do Plano, incluindo reuniões periódicas com gestores, consolidação de indicadores e relatórios de progresso.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(4, '2.1.2', 'Institucionalizar a gestão de projetos', 3, 3, 3, 'AE 2.1.1 (Gestão estratégica) | AE 2.1.3 (Instrumentos institucionais) | AE 2.1.6 (Gestão de processos) | AE 1.1.3 (Fontes de recursos)', 'Adoção de metodologias padronizadas e instituição de ferramentas tecnológicas de suporte que instrumentalizem todo o ciclo de vida da gestão (O QUÊ), visando garantir a viabilidade técnica, o monitoramento da execução e a entrega efetiva de produtos com qualidade e aderência aos prazos (PARA QUÊ).', 'Adoção de metodologias padronizadas e instituição de ferramentas tecnológicas de suporte que instrumentalizem todo o ciclo de vida da gestão.', 'Garantir a viabilidade técnica, o monitoramento da execução e a entrega efetiva de produtos com qualidade e aderência aos prazos.', 'A gestão de projetos é requisito transversal para a execução de qualquer iniciativa estruturante da Secretaria. A Lei Federal nº 12.608/2012 prevê a articulação sistemática entre os entes para ações de proteção e defesa civil, o que pressupõe capacidade de formular, executar e monitorar projetos. A PEPDEC (Decreto nº 46.935/2020) reforça a necessidade de planejamento baseado em estudos e pesquisas (Art. 3º, IV), cuja operacionalização depende de instrumentos de gestão de projetos. O Plano Estratégico 2024–2035 posiciona esta ação como segundo pilar da governança (E2.1), complementar à gestão estratégica (AE 2.1.1): enquanto a AE 2.1.1 mede o alinhamento global da Secretaria à estratégia, a AE 2.1.2 assegura que as iniciativas individuais sejam executadas com método, prazo e qualidade.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(5, '2.1.3', 'Produzir instrumentos institucionais de transparência e comunicação', 3, 3, 3, 'AE 2.1.1 (Gestão estratégica) | AE 2.1.2 (Gestão de projetos) | AE 2.1.4 (Cultura organizacional) | AE 1.1.3 (Fontes de recursos) | AE 7.1.2 (Atuação parlamentar)', 'Desenvolvimento de produtos de comunicação estratégica que sistematizem e evidenciem o valor público das entregas da Defesa Civil (O QUÊ), visando fortalecer o posicionamento da marca, promover a coesão e o alinhamento organizacional e ampliar a credibilidade para a atração de investimentos e parcerias estratégicas (PARA QUÊ).', 'Desenvolvimento de produtos de comunicação estratégica que sistematizem e evidenciem o valor público das entregas da Defesa Civil.', 'Fortalecer o posicionamento institucional, promover a coesão e o alinhamento organizacional e ampliar a credibilidade para a atração de investimentos e parcerias estratégicas.', 'A produção de instrumentos institucionais de transparência responde a um duplo imperativo. Internamente, a Secretaria necessita de produtos que sistematizem suas entregas e tornem visível o trabalho de seus órgãos, promovendo coesão e alinhamento. Externamente, a credibilidade institucional perante financiadores, parceiros e órgãos de controle depende da capacidade de demonstrar, com clareza e regularidade, o valor público das ações realizadas. A Lei Federal nº 12.608/2012 prevê a transparência como princípio da gestão de riscos e desastres. A PEPDEC (Decreto nº 46.935/2020) reforça a necessidade de ampla divulgação das ações de proteção e defesa civil. O Plano Estratégico 2024–2035 posiciona esta ação como complemento direto da gestão estratégica (AE 2.1.1) e da captação de recursos (AE 1.1.3): sem instrumentos que evidenciem resultados, não há como sustentar credibilidade para parcerias nem prestar contas à sociedade.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(6, '2.1.4', 'Fortalecer a cultura e o clima organizacional', 3, 3, 3, 'AE 2.1.1 (Gestão estratégica) | AE 2.1.3 (Instrumentos institucionais) | AE 2.1.7 (Gestão por competências) | AE 3.1.1 (Capacitação do efetivo)', 'Promoção de ações contínuas de internalização da Identidade Estratégica e integração transversal (O QUÊ), visando assegurar que cada servidor compreenda seu papel na missão maior e atue com senso de unidade, ao passo que se fomenta a evolução da maturidade institucional em todos os níveis hierárquicos, consolidando uma cultura orientada a resultados, à inovação e à governança sistêmica (PARA QUÊ).', 'Promoção de ações contínuas de internalização da Identidade Estratégica e integração transversal.', 'Assegurar que cada servidor compreenda seu papel na missão institucional e atue com senso de unidade, fomentando a evolução da maturidade institucional em todos os níveis hierárquicos, consolidando uma cultura orientada a resultados, à inovação e à governança sistêmica.', 'O fortalecimento da cultura organizacional é o eixo que confere coerência e sustentabilidade a todas as demais ações de governança. Metodologias, processos e indicadores só produzem resultado quando internalizados pelas equipes como prática institucional, não como exigência burocrática. O Plano Estratégico 2024–2035 define valores institucionais (sentimento de servidor, engajamento, comprometimento e foco, desenvolvimento pessoal, receptividade, integridade) e posiciona esta ação como instrumento de internalização desses valores. A Lei Federal nº 12.608/2012 e a PEPDEC (Decreto nº 46.935/2020) exigem capacidade de atuação coordenada e multissetorial, o que pressupõe coesão interna e alinhamento entre os órgãos. O Programa SEDEC 360 constitui a iniciativa estruturante que operacionaliza esta ação, promovendo o fortalecimento da governança e da cultura de gestão na Secretaria.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(7, '2.1.5', 'Estabelecer revisão periódica das normas internas', 3, 3, 3, 'AE 2.1.3 (Instrumentos institucionais) | AE 2.1.6 (Gestão de processos) | AE 7.1.1 (Arcabouço normativo externo) | AE 8.2.5 (Conteúdo doutrinário)', 'Instituição de ciclos rotineiros de atualização e validação do arcabouço normativo e doutrinário (O QUÊ), visando garantir a aderência dos ritos operacionais à legislação vigente, a padronização das condutas e a segurança jurídica na tomada de decisão dos gestores (PARA QUÊ).', 'Instituição de ciclos rotineiros de atualização e validação do arcabouço normativo e doutrinário.', 'Garantir a aderência dos ritos operacionais à legislação vigente, a padronização das condutas e a segurança jurídica na tomada de decisão dos gestores.', 'O arcabouço normativo interno (regimentos, protocolos, NGAs e demais instrumentos) é o que traduz a legislação e a estratégia em regras de conduta operacional. Quando desatualizado, gera ambiguidade na tomada de decisão, insegurança jurídica e despadronização de condutas. O Plano Estratégico 2024–2035 prevê esta ação como instrumento de segurança jurídica e padronização, e suas iniciativas exemplificativas incluem o mapeamento do conjunto de normas internas, a inclusão de período de revisão no calendário anual e a criação de Grupos de Trabalho para aprimoramento. A ação é complementar à gestão de processos (AE 2.1.6): enquanto a AE 2.1.6 padroniza os fluxos de trabalho, a AE 2.1.5 assegura que o arcabouço normativo que rege esses fluxos esteja vigente, coerente e acessível. No âmbito externo, a AE 7.1.1 trata do acompanhamento da legislação pertinente à Defesa Civil; a presente AE concentra-se exclusivamente nas normas internas da Secretaria.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(8, '2.1.6', 'Implantar e implementar a gestão de processos', 3, 3, 3, 'AE 2.1.1 (Gestão estratégica) | AE 2.1.2 (Gestão de projetos) | AE 2.1.5 (Revisão de normas) | AE 2.1.7 (Gestão por competências)', 'Mapeamento, padronização e integração dos fluxos de trabalho finalísticos e de suporte sob a ótica da Cadeia de Valor (O QUÊ), visando assegurar a continuidade, a impessoalidade e a conexão eficiente entre as etapas produtivas, promovendo ganhos de eficácia sistêmica e a qualidade das entregas em conformidade com as políticas institucionais (PARA QUÊ).', 'Mapeamento, padronização e integração dos fluxos de trabalho finalísticos e de suporte sob a ótica da Cadeia de Valor.', 'Assegurar a continuidade, a impessoalidade e a conexão eficiente entre as etapas produtivas, promovendo ganhos de eficácia sistêmica e a qualidade das entregas em conformidade com as políticas institucionais.', 'A gestão de processos é o instrumento que transforma atividades dispersas e dependentes de conhecimento individual em fluxos de trabalho padronizados, documentáveis e transferíveis. O Plano Estratégico 2024–2035 posiciona esta ação como pilar da governança (E2.1), com iniciativas que incluem o estabelecimento de metodologia organizacional, a adoção de plataforma para gerenciamento de processos e a difusão dos fundamentos junto à instituição. A ação é diretamente complementar à revisão de normas internas (AE 2.1.5) — enquanto a AE 2.1.5 assegura que as normas estejam vigentes e coerentes, a AE 2.1.6 padroniza os fluxos operacionais que essas normas regem. Ambas, juntas, combatem a execução informal e não rastreada. A gestão de processos também alimenta a gestão por competências (AE 2.1.7): só é possível definir quais competências cada função exige quando os processos que essa função executa estão mapeados.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(9, '2.1.7', 'Implantar e implementar a gestão por competências', 3, 3, 3, 'AE 2.1.4 (Cultura organizacional) | AE 2.1.5 (Revisão de normas/regimentos) | AE 2.1.6 (Gestão de processos) | AE 3.1.1 (Capacitação do efetivo)', 'Estabelecimento de um modelo de gestão que integre o mapeamento, a avaliação e o desenvolvimento contínuo de conhecimentos, habilidades e atitudes (O QUÊ), visando alinhar o capital humano aos objetivos estratégicos da organização e potencializar a performance individual e coletiva (PARA QUÊ).', 'Estabelecimento de um modelo de gestão que integre o mapeamento, a avaliação e o desenvolvimento contínuo de conhecimentos, habilidades e atitudes.', 'Alinhar o capital humano aos objetivos estratégicos da organização e potencializar a performance individual e coletiva.', 'A gestão por competências é o instrumento que conecta as funções da estrutura organizacional às capacidades necessárias para executá-las. O Plano Estratégico 2024–2035 posiciona esta ação com três iniciativas sequenciais: mapear as funções da estrutura, mapear as competências necessárias e desejáveis para cada função, e mapear as competências da força de trabalho. A sequência é deliberada: não é possível definir competências sem antes saber quais funções existem e quais processos cada uma executa. Por isso, esta AE tem dependência direta da gestão de processos (AE 2.1.6): os processos mapeados são o insumo primário para identificar os conhecimentos, habilidades e atitudes que cada função exige. Há também interdependência com a revisão de normas internas (AE 2.1.5): regimentos internos que reflitam com precisão as funções e atribuições de cada setor são base formal para o mapeamento de competências. O Objetivo Estratégico 3 (Desenvolver o efetivo) reforça essa conexão ao prever trilhas de aprendizagem, capacitações e gestão de pessoas por competências com foco estratégico.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(10, '3.1.1', 'Ampliar conhecimento e experiência do efetivo em proteção e defesa civil', 3, 4, 4, 'AE 2.1.4 (Cultura organizacional) | AE 2.1.7 (Gestão por competências) | AE 3.1.2 (Avaliação de performance) | AE 6.1.4 (Extensão acadêmica)', 'Estabelecimento de trilhas de educação continuada e intercâmbio de experiências práticas (O QUÊ), visando elevar o nível de especialização técnica da tropa para atuar com excelência tanto na gestão de riscos quanto no gerenciamento de desastres complexos (PARA QUÊ).', 'Estabelecimento de trilhas de educação continuada e intercâmbio de experiências práticas.', 'Elevar o nível de especialização técnica da tropa para atuar com excelência tanto na gestão de riscos quanto no gerenciamento de desastres complexos.', 'O desenvolvimento do efetivo é o objetivo que conecta a governança à capacidade de execução. Instrumentos de gestão (processos, projetos, indicadores) só geram resultado quando operados por profissionais com conhecimento técnico adequado. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E3.1 (Desenvolvimento e adequação do efetivo), com iniciativas que incluem trilhas de educação continuada e estímulo ao autodesenvolvimento. A ação tem dependência direta da gestão por competências (AE 2.1.7): os diagnósticos de lacuna produzidos pela AE 2.1.7 orientam o que capacitar; a presente AE trata de como capacitar. Sem essa conexão, as capacitações tendem a ser orientadas por demandas avulsas ou por disponibilidade de oferta, e não pelas necessidades reais da instituição. O OE 3 reforça que o fator crítico de sucesso é a liderança patrocinando uma cultura pautada no desenvolvimento pessoal e profissional.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(11, '4.1.1', 'Melhorar acomodação do pessoal, dos recursos e dos serviços necessários à produtividade da defesa civil estadual', 3, 5, 5, 'AE 4.2.1 (Recursos materiais) | AE 4.3.1 (Sistemas tecnológicos) | AE 4.4.1 (Serviços contratados)', 'Adequação e modernização da infraestrutura física e das instalações de trabalho (O QUÊ), visando garantir condições ergonômicas, salubridade e um ambiente propício à alta performance operacional e administrativa das equipes, superando precariedades que impactam a rotina (PARA QUÊ).', 'Adequação e modernização da infraestrutura física e das instalações de trabalho.', 'Garantir condições ergonômicas, salubridade e um ambiente propício à alta performance operacional e administrativa das equipes, superando precariedades que impactam a rotina.', 'A infraestrutura física é a condição material que viabiliza todas as demais ações estratégicas. Não é possível exigir alta performance de equipes que operam em instalações precárias, sem condições ergonômicas adequadas ou sem espaço para as atividades que a estratégia prevê. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E4.1, com duas frentes: otimizar as instalações existentes e prover soluções para desenvolvimento da infraestrutura. A ação é complementar às demais AEs do OE 4: enquanto a AE 4.1.1 trata das instalações físicas, as AEs 4.2.1, 4.3.1 e 4.4.1 tratam, respectivamente, de recursos materiais, sistemas tecnológicos e serviços contratados. Juntas, compõem o suporte material para a missão institucional.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(12, '4.3.1', 'Melhorar sistemas tecnológicos necessários à produtividade da defesa civil estadual', 3, 5, 6, 'AE 4.1.1 (Infraestrutura física) | AE 4.2.1 (Recursos materiais) | AE 4.4.1 (Serviços contratados)', 'Modernização e aquisição de ativos tecnológicos e soluções de software, abrangendo desde ferramentas de produtividade corporativa transversal até sistemas técnicos para setores especializados (O QUÊ), visando automatizar rotinas, eliminar gargalos operacionais e elevar a eficiência e a capacidade de entrega das equipes (PARA QUÊ).', 'Modernização e aquisição de ativos tecnológicos e soluções de software, abrangendo desde ferramentas de produtividade corporativa transversal até sistemas técnicos para setores especializados.', 'Automatizar rotinas, eliminar gargalos operacionais e elevar a eficiência e a capacidade de entrega das equipes.', 'Os sistemas tecnológicos são a infraestrutura digital que suporta a execução das atividades da Secretaria. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E4.3, com duas frentes: otimizar os sistemas de informação existentes e prover soluções para desenvolvimento e modernização da rede tecnológica. A ação abrange desde ferramentas de produtividade corporativa transversal até sistemas técnicos especializados. A ação é complementar às demais AEs do OE 4, que tratam respectivamente de infraestrutura física (AE 4.1.1), recursos materiais (AE 4.2.1) e serviços contratados (AE 4.4.1).', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(13, '4.4.1', 'Aprimorar rede de serviços contratados necessários à produtividade da defesa civil estadual', 3, 5, 7, 'AE 4.1.1 (Infraestrutura física) | AE 4.2.1 (Recursos materiais) | AE 4.3.1 (Sistemas tecnológicos)', 'Otimização e gestão estratégica do portfólio de contratos de serviços continuados e sob demanda (O QUÊ), visando garantir a sustentabilidade das rotinas administrativas e a prontidão operacional, assegurando que a estrutura de apoio suporte plenamente a missão institucional tanto em tempos de normalidade quanto em crises (PARA QUÊ).', 'Otimização e gestão estratégica do portfólio de contratos de serviços continuados e sob demanda.', 'Garantir a sustentabilidade das rotinas administrativas e a prontidão operacional, assegurando que a estrutura de apoio suporte plenamente a missão institucional tanto em tempos de normalidade quanto em crises.', 'Os serviços contratados sustentam a rotina administrativa e operacional da Secretaria — desde serviços de apoio logístico até contratações especializadas sob demanda. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E4.4, com duas frentes: aperfeiçoar os contratos vigentes para melhor atender às necessidades da defesa civil e adequar as novas contratações às demandas atuais. O OE 4 destaca como fatores críticos de sucesso a celeridade e a qualidade técnica na instrução dos processos de contratação. A ação é complementar às demais AEs do OE 4, que tratam respectivamente de infraestrutura física (AE 4.1.1), recursos materiais (AE 4.2.1) e sistemas tecnológicos (AE 4.3.1).', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(14, '6.1.3', 'Implantar parcerias para implementação de projetos de pesquisa e extensão técnico-científica (Estrutura SEDEC e COMDECs)', 4, 6, 8, 'AE 6.1.1 (Ecossistema colaborativo) | AE 6.1.4 (Extensão acadêmica) | AE 6.1.6 (Redes de pesquisa) | AE 1.1.3 (Fontes de recursos)', 'Promoção da integração técnica e do alinhamento entre a SEDEC e as Defesas Civis Municipais (COMDECs) para o desenvolvimento colaborativo de iniciativas de ciência e extensão (O QUÊ), visando solucionar gargalos operacionais específicos das pontas, promover o intercâmbio de saberes e fortalecer a coesão do Sistema Estadual através de uma rede de conhecimento aplicado (PARA QUÊ).', 'Promoção da integração técnica e do alinhamento entre a SEDEC e as Defesas Civis Municipais (COMDECs) para o desenvolvimento colaborativo de iniciativas de ciência e extensão.', 'Solucionar gargalos operacionais específicos das pontas, promover o intercâmbio de saberes e fortalecer a coesão do Sistema Estadual através de uma rede de conhecimento aplicado.', 'A produção de conhecimento aplicado é uma das missões centrais do ICTDEC e condição para que a Defesa Civil evolua de uma atuação baseada em empirismo para uma prática fundamentada em ciência. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.1 (Estruturação da atividade de C&T), com foco específico na integração entre a SEDEC e as Defesas Civis Municipais (COMDECs) para o desenvolvimento colaborativo de pesquisa e extensão. A iniciativa indicada é a disseminação de informação técnico-científica para pesquisadores da estrutura SEDEC e do SIEPDEC. A ação se articula com a AE 6.1.1 (ecossistema colaborativo com IES e ICTs), a AE 6.1.4 (extensão acadêmica), a AE 6.1.6 (redes de pesquisa) e a AE 1.1.3 (fontes de recursos), pois parcerias de pesquisa são também vetor de captação de recursos via editais de fomento.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(15, '6.1.4', 'Construir programa de extensão Acadêmico-Científica articulando a formação em serviço (SEDEC e IES e ICTs)', 3, 6, 8, 'AE 6.1.1 (Ecossistema colaborativo) | AE 6.1.3 (Parcerias de pesquisa e extensão) | AE 6.1.6 (Redes de pesquisa) | AE 3.1.1 (Capacitação do efetivo)', 'Estruturação de programas de residência, estágio técnico e intercâmbio acadêmico integrados à rotina operacional (O QUÊ), visando oxigenar a instituição com novos saberes, qualificar a formação dos futuros profissionais do setor através da prática supervisionada e aproximar a academia da realidade da gestão pública (PARA QUÊ).', 'Estruturação de programas de residência, estágio técnico e intercâmbio acadêmico integrados à rotina operacional.', 'Oxigenar a instituição com novos saberes, qualificar a formação dos futuros profissionais do setor através da prática supervisionada e aproximar a academia da realidade da gestão pública.', 'A extensão acadêmico-científica é o mecanismo que conecta a formação de novos profissionais à realidade operacional da Defesa Civil. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.1 (Estruturação da atividade de C&T), com foco na estruturação de programas de residência, estágio técnico e intercâmbio acadêmico integrados à rotina operacional. A ação gera duplo benefício: oxigena a instituição com novos saberes e qualifica a formação dos futuros profissionais do setor por meio da prática supervisionada. A ação se articula diretamente com a AE 6.1.3 (parcerias de pesquisa), pois compartilha o mesmo ecossistema de parcerias com IES e ICTs, e com a AE 3.1.1 (capacitação do efetivo), pois os programas de extensão também contribuem para a qualificação interna.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(16, '6.1.6', 'Compor redes e projetos estaduais, nacionais e internacionais de pesquisa científica e tecnológica voltadas para ações de inovação tecnológica', 4, 6, 8, 'AE 6.1.1 (Ecossistema colaborativo) | AE 6.1.3 (Parcerias de pesquisa) | AE 6.1.4 (Extensão acadêmica) | AE 1.1.3 (Fontes de recursos)', 'Integração institucional a ecossistemas de inovação e redes de colaboração multi-institucionais (O QUÊ), visando posicionar a Defesa Civil do Estado na vanguarda tecnológica, atrair parcerias qualificadas e fomentar o desenvolvimento de soluções para a redução de desastres (PARA QUÊ).', 'Integração institucional a ecossistemas de inovação e redes de colaboração multi-institucionais.', 'Posicionar a Defesa Civil do Estado na vanguarda tecnológica, atrair parcerias qualificadas e fomentar o desenvolvimento de soluções para a redução de desastres.', 'A integração a redes de pesquisa e ecossistemas de inovação é o que permite à Defesa Civil do Estado transitar do isolamento institucional para o posicionamento como ator científico reconhecido. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.1, com foco específico na composição de redes e projetos multi-institucionais nas escalas estadual, nacional e internacional. A iniciativa indicada é o mapeamento dos principais grupos de estudos e pesquisas científicas em defesa civil, visando a inserção dos órgãos tecnológicos, de ensino e pesquisa da estrutura SEDEC. A ação é complementar às AEs 6.1.3 (parcerias de pesquisa) e 6.1.4 (extensão acadêmica), que operam na escala bilateral; esta AE opera na escala de rede. Conecta-se também à AE 1.1.3 (fontes de recursos), pois a participação em redes amplia o acesso a editais de fomento nacionais e internacionais.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(17, '6.2.1', 'Promover a inovação institucional, a partir dos órgãos científicos, tecnológicos e de ensino da SEDEC', 3, 6, 9, 'AE 2.1.6 (Gestão de processos) | AE 6.1.3 (Parcerias de pesquisa) | AE 6.3.2 (Sistematização do conhecimento) | AE 6.4.1 (Inovações incrementais)', 'Fomento interno à Pesquisa, Desenvolvimento e Inovação (PD&I) focado na resolução de problemas organizacionais (O QUÊ), visando transformar a análise crítica dos processos em novos produtos ou serviços que aumentem a eficiência das iniciativas da secretaria, fundamentando a evolução institucional em ciência aplicada (PARA QUÊ).', 'Fomento interno à Pesquisa, Desenvolvimento e Inovação (PD&I) focado na resolução de problemas organizacionais.', 'Transformar a análise crítica dos processos em novos produtos ou serviços que aumentem a eficiência das iniciativas da Secretaria, fundamentando a evolução institucional em ciência aplicada.', 'A inovação institucional é o que transforma a análise crítica dos problemas organizacionais em soluções concretas — novos produtos, serviços ou processos que elevem a eficiência da Secretaria. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.2 (Promoção da Inovação), com foco em Pesquisa, Desenvolvimento e Inovação (PD&I) internos. A iniciativa indicada é o estabelecimento de uma NGA sobre inovação com parâmetros, metas e indicadores de avaliação. O OE 6 destaca como fator crítico de sucesso a receptividade da cultura organizacional à incorporação de novas tecnologias e doutrinas. A ação se articula com a AE 2.1.6 (gestão de processos), que gera os diagnósticos de gargalos que alimentam a inovação; com a AE 6.3.2 (sistematização do conhecimento), que captura o saber tácito que pode ser transformado em inovação; e com a AE 6.4.1 (inovações incrementais), que aplica os resultados.', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(18, '6.3.1', 'Promover a sistematização de saberes/fazeres no âmbito dos municípios de modo a dar visibilidade para as ações técnico-científicas desenvolvidas no âmbito do Estado do Rio de Janeiro', 4, 6, 10, 'AE 6.3.2 (Conhecimento interno SEDEC) | AE 6.3.3 (Registro histórico) | AE 6.2.1 (PD&I institucional) | AE 6.1.3 (Parcerias de pesquisa)', 'Implementação de uma estratégia corporativa de Gestão do Conhecimento e Inteligência Coletiva (O QUÊ), capaz de capturar, validar cientificamente e sistematizar o capital intelectual gerado em todas as instâncias do Sistema (O QUÊ), visando transformar experiências operacionais e práticas locais dispersas em doutrina técnica consolidada, conferindo caráter científico e visibilidade institucional às ações de Defesa Civil (PARA QUÊ).', 'Implementação de uma estratégia corporativa de Gestão do Conhecimento e Inteligência Coletiva, capaz de capturar, validar cientificamente e sistematizar o capital intelectual gerado em todas as instâncias do Sistema.', 'Transformar experiências operacionais e práticas locais dispersas em doutrina técnica consolidada, conferindo caráter científico e visibilidade institucional às ações de Defesa Civil.', 'O Sistema Estadual de Proteção e Defesa Civil produz conhecimento diariamente — nas operações municipais, nos relatos de campo, nas soluções improvisadas diante de desastres. Esse capital intelectual, porém, permanece disperso e não documentado. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.3 (Fomento da Produção de Conhecimento), com foco na implementação de uma estratégia corporativa de Gestão do Conhecimento e Inteligência Coletiva. A iniciativa indicada é a abertura de chamadas sistemáticas para receber estudos, pesquisas e relatos de experiências desenvolvidas no âmbito dos municípios. A ação complementa a AE 6.3.2 (sistematização do conhecimento interno da SEDEC) e alimenta a AE 6.2.1 (PD&I institucional) e a AE 6.3.3 (registro histórico).', NULL, '1.0', '2026-02-14', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(19, '6.3.2', 'Sistematizar o conhecimento acumulado pelo pessoal da estrutura SEDEC, passível de aplicação em projetos de pesquisa, desenvolvimento e inovação', 3, 6, 10, 'AE 6.3.1 (Saberes municipais) | AE 6.3.3 (Registro histórico) | AE 6.2.1 (PD&I institucional) | AE 2.1.4 (Cultura organizacional)', 'Estabelecimento de rotinas para identificar, registrar e estruturar o conhecimento tácito e as experiências operacionais do efetivo (O QUÊ), visando transformar vivências práticas em base técnica para alimentar linhas de pesquisa, subsidiar o desenvolvimento de novas tecnologias e fomentar a inovação aplicada às necessidades do sistema (PARA QUÊ).', 'Estabelecimento de rotinas para identificar, registrar e estruturar o conhecimento tácito e as experiências operacionais do efetivo.', 'Transformar vivências práticas em base técnica para alimentar linhas de pesquisa, subsidiar o desenvolvimento de novas tecnologias e fomentar a inovação aplicada às necessidades do sistema.', 'O efetivo da SEDEC acumula décadas de experiência operacional em gestão de riscos e desastres — conhecimento que existe na prática, nos relatos informais e na memória individual, mas que não está registrado nem estruturado. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.3 (Fomento da Produção de Conhecimento), com foco no estabelecimento de rotinas para identificar, registrar e estruturar o conhecimento tácito e as experiências operacionais do efetivo. A iniciativa indicada é a avaliação constante a partir de exercícios simulados e painéis pós-desastres. A ação complementa a AE 6.3.1 (saberes dos municípios), formando com ela o conjunto completo da gestão do conhecimento do Sistema. O conhecimento sistematizado alimenta diretamente a AE 6.2.1 (PD&I institucional) e a AE 6.3.3 (registro histórico).', NULL, '1.0', '2026-02-16', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(20, '6.3.3', 'Garantir o registro histórico, técnico, tecnológico e científico das ações, serviços e processos de formação e capacitação científica e tecnológica', 3, 6, 10, 'AE 6.3.1 (Saberes municipais) | AE 6.3.2 (Conhecimento interno) | AE 6.5.1 (Ciclo da informação) | AE 6.2.1 (PD&I institucional)', 'Organização, digitalização e preservação do acervo documental e da memória técnica institucional (O QUÊ), visando assegurar a rastreabilidade das evoluções doutrinárias e fornecer substrato auditável para estudos longitudinais sobre a gestão de desastres no Estado (PARA QUÊ).', 'Organização, digitalização e preservação do acervo documental e da memória técnica institucional.', 'Assegurar a rastreabilidade das evoluções doutrinárias e fornecer substrato auditável para estudos longitudinais sobre a gestão de desastres no Estado.', 'As ações 6.3.1 e 6.3.2 capturam e sistematizam conhecimento novo — dos municípios e do efetivo, respectivamente. Esta ação complementa o ciclo ao garantir que todo esse conhecimento, junto com o acervo histórico já existente, seja preservado, organizado e acessível. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.3 (Fomento da Produção de Conhecimento), com foco na organização, digitalização e preservação do acervo documental e da memória técnica institucional. A iniciativa indicada é a construção de uma publicação anual ou semestral que registre o histórico dos campos teórico, técnico, científico, operativo e gerencial da instituição. A ação articula-se também com a AE 6.5.1 (ciclo da informação), pois a memória técnica é parte essencial da governança de dados institucional.', NULL, '1.0', '2026-02-16', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(21, '6.4.1', 'Mapear produtos, processos ou serviços que compreendam a agregação de novas funcionalidades ou características, desde que possam resultar em melhorias ou em efetivo ganho de qualidade ou desempenho', 3, 6, 11, 'AE 6.2.1 (PD&I institucional) | AE 6.3.2 (Conhecimento interno) | AE 2.1.6 (Gestão de processos) | AE 4.3.1 (Sistemas tecnológicos)', 'Sistematização do levantamento de inovações incrementais aplicáveis aos ativos, fluxos e serviços já em operação (O QUÊ), visando promover a atualização funcional e o ganho efetivo de desempenho nas atividades finalísticas de avaliação, redução de riscos e gestão de desastres, maximizando o potencial das soluções vigentes sem a necessidade de substituição total (PARA QUÊ).', 'Sistematização do levantamento de inovações incrementais aplicáveis aos ativos, fluxos e serviços já em operação.', 'Promover a atualização funcional e o ganho efetivo de desempenho nas atividades finalísticas de avaliação, redução de riscos e gestão de desastres, maximizando o potencial das soluções vigentes sem a necessidade de substituição total.', 'As estratégias E6.2 e E6.3 produzem conhecimento e inovação. Esta ação fecha o ciclo ao garantir que esse conhecimento chegue à operação. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.4 (Aplicação dos Conhecimentos Produzidos), com foco na sistematização do levantamento de inovações incrementais aplicáveis aos ativos, fluxos e serviços já em operação. A iniciativa indicada é estimular o uso e a aplicação dos conhecimentos produzidos institucionalmente e pelas IES/ICTs em cooperação técnica. A ação conecta-se diretamente à AE 6.2.1 (PD&I), cujos produtos alimentam este mapeamento, e à AE 2.1.6 (gestão de processos), que fornece a visão dos fluxos passíveis de melhoria.', NULL, '1.0', '2026-02-16', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(22, '6.5.1', 'Mapear o ciclo da informação: produção, organização/sistematização, armazenamento, disseminação, divulgação e uso na estrutura SEDEC', 3, 6, 12, 'AE 6.5.2 (Metafonte) | AE 6.3.3 (Memória técnica) | AE 2.1.6 (Gestão de processos) | AE 4.3.1 (Sistemas tecnológicos)', 'Estabelecimento de diretrizes de governança de dados e protocolos de fluxo informacional (O QUÊ), visando transformar dados dispersos em ativos de conhecimento institucional acessíveis, garantindo a preservação da memória técnica e a disponibilidade de informações confiáveis para subsidiar a tomada de decisão em todos os níveis (PARA QUÊ).', 'Estabelecimento de diretrizes de governança de dados e protocolos de fluxo informacional.', 'Transformar dados dispersos em ativos de conhecimento institucional acessíveis, garantindo a preservação da memória técnica e a disponibilidade de informações confiáveis para subsidiar a tomada de decisão em todos os níveis.', 'A informação é o insumo mais crítico da Defesa Civil — da emissão de alertas à tomada de decisão estratégica. No entanto, não existe um mapeamento de como a informação é produzida, organizada, armazenada, disseminada e utilizada dentro da SEDEC. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E6.5 (Aprimoramento da Gestão da Informação), com foco no estabelecimento de diretrizes de governança de dados e protocolos de fluxo informacional. A iniciativa indicada é identificar atores, dispositivos legais, sistemas de armazenamento e organização, sistemas de disseminação “entre os pares”, divulgação “para todos os públicos” e modos de apropriação (uso e aplicação) da informação. A ação é pré-requisito para a AE 6.5.2 (Metafonte) e complementa a AE 6.3.3 (memória técnica).', NULL, '1.0', '2026-02-16', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(25, '8.1.5', 'Atuar em colaboração com os municípios nas ações de prevenção e mitigação', 5, 8, 14, 'AE 8.1.3 (Autonomia em alerta/alarme) | AE 8.1.4 (Captação de recursos federais) | AE 8.2.7 (Colaboração em preparação e resposta) | AE 10.1.2 (Projetos comunitários)', 'Estabelecimento de um regime de cooperação técnica e institucional multifacetado, abrangendo desde o suporte ao ordenamento territorial e normatização até a articulação para viabilização de medidas estruturais e não estruturais (O QUÊ), visando não apenas a instrumentalização da gestão local, mas a efetiva redução das vulnerabilidades e riscos preexistentes no território fluminense (PARA QUÊ).', 'Estabelecimento de um regime de cooperação técnica e institucional multifacetado, abrangendo desde o suporte ao ordenamento territorial e normatização até a articulação para viabilização de medidas estruturais e não estruturais.', 'Não apenas a instrumentalização da gestão local, mas a efetiva redução das vulnerabilidades e riscos preexistentes no território fluminense.', 'A redução de vulnerabilidades e riscos no território fluminense depende de ações de prevenção e mitigação executadas nos municípios — mas a maioria não dispõe de capacidade técnica, científica e institucional para conduzi-las sozinha. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E8.1, com foco no estabelecimento de um regime de cooperação técnica e institucional multifacetado: desde o suporte ao ordenamento territorial e à normatização até a articulação para viabilização de medidas estruturais e não estruturais. A iniciativa indicada é apoiar com recursos estaduais projetos de prevenção e mitigação. A ação mobiliza múltiplos órgãos da Defesa Civil Estadual, cada um na sua competência.', NULL, '1.0', '2026-02-17', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(26, '8.2.5', 'Desenvolver conteúdo doutrinário para apoio às ações de preparação e resposta', 5, 8, 15, 'AE 8.2.1 (Alinhamento operacional em resposta) | AE 8.2.7 (Colaboração com municípios) | AE 6.3.3 (Memória técnica) | AE 2.1.5 (Revisão de normas internas)', 'Prestação de assessoria técnica e fomento às estratégias de planejamento de contingência, somada à mobilização de suporte operacional direto e complementar em situações de crise (O QUÊ), visando instrumentalizar a prontidão local e assegurar a suficiência da resposta estatal quando a capacidade de atendimento municipal for excedida (PARA QUÊ).', 'Produção e atualização de manuais técnicos, POPs e guias de referência.', 'A padronização tática das equipes e a preservação do conhecimento operacional acumulado pela instituição.', 'A Secretaria acumula décadas de experiência operacional em preparação e resposta a desastres. No entanto, esse conhecimento está concentrado em pessoas, não em documentos. Manuais técnicos são escassos, POPs inexistem ou estão desatualizados, e os guias de referência não refletem as lições aprendidas nas operações mais recentes. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E8.2 (Aprimoramento dos serviços de preparação e resposta), com foco na produção e atualização de conteúdo doutrinário. As iniciativas indicadas incluem a criação do manual de funcionamento dos Gabinetes Integrados de Gestão de Desastres (GIGD) e a produção de conteúdo de apoio aos municípios sobre estruturas de suporte a desastres.', NULL, '1.0', '2026-02-17', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(27, '8.2.7', 'Atuar em colaboração com os municípios nas ações de preparação e resposta', 5, 8, 15, 'AE 8.1.5 (Colaboração em prevenção/mitigação) | AE 8.2.1 (Alinhamento operacional) | AE 8.2.5 (Conteúdo doutrinário) | AE 8.1.3 (Autonomia em alerta/alarme)', 'Prestação de assessoria técnica e fomento às estratégias de planejamento de contingência, somada à mobilização de suporte operacional direto e complementar em situações de crise (O QUÊ), visando instrumentalizar a prontidão local e assegurar a suficiência da resposta estatal quando a capacidade de atendimento municipal for excedida (PARA QUÊ).', 'Prestação de assessoria técnica e fomento às estratégias de planejamento de contingência, somada à mobilização de suporte operacional direto e complementar em situações de crise.', 'Instrumentalizar a prontidão local e assegurar a suficiência da resposta estatal quando a capacidade de atendimento municipal for excedida.', 'A capacidade de resposta a desastres no Estado depende da preparação dos municípios. Quando a capacidade municipal é excedida, o Estado é chamado a complementar — mas a qualidade dessa complementação depende de articulação prévia, não de improvisação durante a crise. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E8.2, com duas dimensões complementares: a prestação de assessoria técnica para o planejamento de contingência municipal (preparação) e a mobilização de suporte operacional direto quando a capacidade local for excedida (resposta). A iniciativa indicada é apoiar com recursos estaduais projetos de preparação e resposta.', NULL, '1.0', '2026-02-17', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(28, '8.3.1', 'Articular aparato estatal para apoiar projetos de recuperação quando solicitado pelos municípios', 4, 8, 16, 'AE 8.3.2 (Conscientização para melhor reconstruir) | AE 8.3.3 (Captação de recursos federais para recuperação) | AE 8.3.4 (Colaboração com municípios na recuperação) | AE 8.2.7 (Colaboração em preparação/resposta)', 'Estabelecimento de fluxos transversais de comunicação intersetorial e definição de critérios técnicos de priorização (O QUÊ), visando assegurar uma atuação integrada do Estado, direcionada às infraestruturas críticas e fundamentada em avaliações de danos auditáveis (PARA QUÊ).', 'Estabelecimento de fluxos transversais de comunicação intersetorial e definição de critérios técnicos de priorização.', 'Assegurar uma atuação integrada do Estado, direcionada às infraestruturas críticas e fundamentada em avaliações de danos auditáveis.', 'A recuperação pós-desastre exige capacidades que estão fora da Defesa Civil: obras de infraestrutura, habitação, saneamento, energia, rodovias, equipamentos públicos. A SEDEC não executa recuperação — articula o aparato estatal para que os órgãos competentes o façam, de forma integrada e priorizada. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E8.3, com foco no estabelecimento de fluxos transversais de comunicação intersetorial e na definição de critérios técnicos de priorização, direcionados às infraestruturas críticas e fundamentados em avaliações de danos auditáveis. A iniciativa indicada é normatizar o procedimento para recebimento dessa demanda.', NULL, '1.0', '2026-02-17', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(29, '8.3.2', 'Promover conscientização dos órgãos estaduais relacionados às ações de recuperação quanto aos princípios para melhor reconstruir após desastres', 4, 8, 16, 'AE 8.3.1 (Articulação do aparato estatal) | AE 8.3.4 (Colaboração com municípios na recuperação) | AE 9.2.1 (Políticas transversais de RRD)', 'Construção e difusão de diretrizes de redução de riscos junto aos órgãos executores de obras e infraestrutura (O QUÊ), visando evitar a reconstrução de cenários de vulnerabilidade e promover a resiliência em investimentos de recuperação (PARA QUÊ).', 'Construção e difusão de diretrizes de redução de riscos junto aos órgãos executores de obras e infraestrutura.', 'Evitar a reconstrução de cenários de vulnerabilidade e promover a resiliência em investimentos de recuperação.', 'A recuperação pós-desastre é uma oportunidade para reduzir vulnerabilidades. O princípio de “reconstruir melhor” (build back better), previsto no Marco de Sendai e incorporado pelo PN-PDC 2025–2035, orienta que as ações de recuperação não reproduzam os cenários de risco que existiam antes do desastre. No entanto, os órgãos estaduais que executam obras e intervenções de infraestrutura não necessariamente incorporam esses princípios em seus projetos. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E8.3, com foco na construção e difusão de diretrizes de redução de riscos junto aos órgãos executores. As iniciativas indicadas são o desenvolvimento de atividades de nivelamento e a produção de mídias para difusão.', NULL, '1.0', '2026-02-17', 'ICTDEC/DAEAD', 'Fase 2 — Desdobramento Orientado (definição de entregas por setor)', '2026-02-21 12:05:31.311365+00', '2026-02-21 12:05:31.311365+00'),
	(30, '9.2.1', 'Implementar mecanismos que viabilizem discussões relacionadas ao desenvolvimento de políticas de RRD transversais e integradas', 4, 9, 17, 'AE 8.3.2 (Conscientização para melhor reconstruir) | AE 9.1.1 (Ferramentas de compreensão de riscos) | AE 9.1.2 (Planos de RRD) | AE 5.1.1 (Integração do SIEPDEC)', 'Estabelecimento de instâncias de articulação intersetorial ampliada, envolvendo atores externos e parceiros estratégicos (O QUÊ), visando qualificar o debate técnico e assegurar a transversalidade da redução de riscos nas múltiplas agendas de governo e sua plena integração ao planejamento global de desenvolvimento do Estado (PARA QUÊ).', 'Estabelecimento de instâncias de articulação intersetorial ampliada, envolvendo atores externos e parceiros estratégicos.', 'Qualificar o debate técnico e assegurar a transversalidade da redução de riscos nas múltiplas agendas de governo e sua plena integração ao planejamento global de desenvolvimento do Estado.', 'A redução de riscos de desastres não se resolve dentro da Defesa Civil. Ela depende de políticas públicas de ordenamento territorial, saúde, educação, meio ambiente, infraestrutura, habitação e outras áreas que não estão sob gestão da SEDEC. O Plano Estratégico 2024–2035 posiciona esta ação na Estratégia E9.2, com foco no estabelecimento de instâncias de articulação intersetorial ampliada que envolvam atores externos e parceiros estratégicos, qualificando o debate técnico e assegurando a transversalidade da RRD nas múltiplas agendas de governo. As iniciativas indicadas incluem capacitação voltada para produção de política pública transversal e integrada de RRD e a realização de reuniões ou eventos periódicos. A PEPDEC (Parágrafo Único do Art. 2º) já determina a integração com políticas de ordenamento territorial, desenvolvimento urbano, saúde, meio ambiente, mudanças climáticas e demais políticas setoriais.', 'Lacuna estrutural identificada
