INSERT INTO "public"."destaque_linhas" ("id", "destaque_id", "ordem", "tipo", "label", "conteudo", "created_at") VALUES
	(1, 1, 1, 'label_conteudo', 'Princípio', 'Municípios que desejam implementar projetos de proteção comunitária frequentemente não sabem por onde começar. Não têm metodologias, modelos de projeto nem materiais de referência. O resultado é que iniciativas locais dependem da capacidade individual de cada gestão municipal, gerando disparidade na qualidade e na continuidade das ações. Esta ação resolve esse problema criando um portfólio de projetos-prateleira: modelos prontos, testados e replicáveis, que o município adere e adapta à sua realidade. O portfólio reduz a barreira de entrada e padroniza a qualidade das iniciativas comunitárias em todo o Estado.', '2026-02-21 12:05:31.311365+00'),
	(2, 1, 2, 'label_conteudo', 'O ciclo de produção', 'Coleta de práticas: as REDECs (via DREDEC) colhem junto aos municípios as melhores práticas de projetos comunitários em PDC já existentes.
INSERT INTO "public"."entrega_participantes" ("id", "entrega_id", "setor_id", "tipo_participante", "papel", "created_at") VALUES
	(4, 2, 11, 'setor', 'operacional', '2026-02-21 19:51:12.568625+00'),
	(5, 2, 16, 'setor', 'grac', '2026-02-21 19:51:12.568625+00');
INSERT INTO "public"."fichas" ("id", "acao_estrategica_id", "ordem", "titulo", "setor_display", "papel", "justificativa", "contribuicao_esperada", "nao_escopo", "dependencias_criticas", "created_at") VALUES
	(1, 1, 1, 'DGAC — LÍDER DA AÇÃO', 'DGAC', 'LÍDER DA AÇÃO', 'A DGAC é o órgão responsável pela conscientização comunitária e pela promoção da percepção de risco. Nesta ação, lidera o ciclo completo: cria, analisa, sistematiza e modela os projetos-prateleira de proteção comunitária. Define o escopo de cada projeto, elabora materiais de apoio, roteiros de implementação e critérios de adaptação local. A DGAC detém o conhecimento sobre as dinâmicas comunitárias e sobre os formatos que geram engajamento nas comunidades. Quando necessário, solicita ao ICTDEC (com CEPEDEC) suporte científico e metodológico específico.', '{"Liderar o ciclo completo de produção do portfólio: criação, análise, sistematização e modelagem dos projetos-prateleira","Definir escopo, materiais de apoio, roteiros de implementação e critérios de adaptação local","Analisar e sistematizar as práticas coletadas pelas REDECs, identificando elementos replicáveis","Validar a aplicabilidade comunitária dos projetos antes da disponibilização no portfólio","Solicitar ao ICTDEC suporte científico quando a análise exigir rigor metodológico específico"}', '{"Não capacitar formalmente agentes municipais (competência da ESDEC)","Não coletar práticas nos municípios (competência das REDECs via DREDEC)"}', '{"Práticas coletadas pelas REDECs como matéria-prima","Validação estratégica da SUOP","Suporte científico do ICTDEC/CEPEDEC quando solicitado","Capacitação da ESDEC para viabilizar a implementação municipal"}', '2026-02-21 12:05:31.311365+00'),
	(2, 1, 2, 'ICTDEC (com CEPEDEC) — SUPORTE CIENTÍFICO SOB DEMANDA', 'ICTDEC (com CEPEDEC)', 'SUPORTE CIENTÍFICO SOB DEMANDA', 'O ICTDEC, por meio do CEPEDEC, é o produtor de conhecimento científico e metodologias da Secretaria. Nesta ação, atua sob demanda da DGAC: quando a análise ou sistematização das práticas comunitárias exigir rigor científico específico — como aplicação de metodologias estatísticas robustas, validação técnico-científica de modelos ou produção de referências acadêmicas —, o ICTDEC é acionado. A liderança da criação, análise e sistematização permanece com a DGAC.', '{"Fornecer suporte científico e metodológico à DGAC quando solicitado","Aplicar metodologias estatísticas robustas quando a análise das práticas exigir","Validar tecnicamente modelos de projeto que demandem fundamentação científica específica","Apoiar a ESDEC com conteúdo científico para capacitação, quando solicitado"}', '{"Não liderar a criação, análise ou sistematização das práticas (competência da DGAC)","Não modelar projetos-prateleira (competência da DGAC)","Não difundir o portfólio aos municípios (competência das REDECs via DREDEC)","Não conduzir capacitações (competência da ESDEC)"}', '{"Demandas específicas da DGAC sobre temas que exijam rigor científico","Acesso às práticas já coletadas e pré-analisadas pela DGAC","Parcerias com IES e ICTs (AE 6.1.3) como fonte complementar de conhecimento"}', '2026-02-21 12:05:31.311365+00'),
	(3, 1, 3, 'ESDEC — CAPACITADORA', 'ESDEC', 'CAPACITADORA', 'A ESDEC capacita agentes do SIEPDEC-RJ. Nesta ação, forma agentes municipais para a implementação dos projetos do portfólio: como aplicar as metodologias, adaptar os projetos à realidade local, engajar comunidades e monitorar resultados. Os conteúdos são fornecidos pela DGAC (modelagem) e pelo ICTDEC (fundamentação metodológica).', '{"Estruturar e executar capacitações para agentes municipais na implementação dos projetos do portfólio","Incluir conteúdos de aplicação de metodologias, adaptação local, engajamento comunitário e monitoramento","Avaliar o aprendizado e retroalimentar o modelo de capacitação"}', '{"Não modelar projetos (competência da DGAC)","Não sistematizar práticas (competência do ICTDEC/CEPEDEC)","Não articular adesão municipal (competência das REDECs via DREDEC)"}', '{"Conteúdos fornecidos pela DGAC e pelo ICTDEC/CEPEDEC","Demanda dimensionada pela SUOP","Apoio logístico das REDECs para capacitação no território"}', '2026-02-21 12:05:31.311365+00'),
	(4, 1, 4, 'REDECs (via DREDEC) — COLETA DE PRÁTICAS E DIFUSÃO AOS MUNICÍPIOS', 'REDECs (via DREDEC)', 'COLETA DE PRÁTICAS E DIFUSÃO AOS MUNICÍPIOS', 'As REDECs são o elo entre o Estado e os municípios. Nesta ação, atuam nas duas pontas do ciclo: na entrada, colhem junto aos municípios e COMDECs as melhores práticas de projetos comunitários em PDC já existentes, alimentando o ICTDEC com matéria-prima para sistematização; na saída, disponibilizam o portfólio aos municípios, articulam a adesão e acompanham a implementação.', '{"Colher junto aos municípios e COMDECs as melhores práticas de projetos comunitários em PDC","Disponibilizar o portfólio de projetos aos municípios de sua região","Articular a adesão municipal aos projetos do portfólio","Acompanhar e reportar a implementação dos projetos nos municípios"}', '{"Não modelar projetos (competência da DGAC)","Não sistematizar metodologicamente (competência do ICTDEC/CEPEDEC)","Não capacitar formalmente agentes municipais (competência da ESDEC)","Não formalizar convênios sem aprovação da SUBSEGAD e validação da ASSEJUR"}', '{"Orientações da DGAC sobre o que coletar e como difundir","Portfólio finalizado e validado para disponibilização","Priorização de municípios definida pela SUOP"}', '2026-02-21 12:05:31.311365+00'),
	(5, 1, 5, 'SUOP (sob aval da SUBSEGOP) — VALIDAÇÃO E COORDENAÇÃO', 'SUOP (sob aval da SUBSEGOP)', 'VALIDAÇÃO E COORDENAÇÃO', 'A SUOP comanda os órgãos setoriais. Nesta ação, valida o portfólio quanto ao alinhamento ao Plano Estratégico, coordena a integração entre os órgãos envolvidos (DGAC, ICTDEC, ESDEC, REDECs) e define critérios de priorização de municípios para difusão e capacitação.', '{"Validar o portfólio quanto ao alinhamento ao Plano Estratégico e às prioridades da SEDEC","Coordenar a integração entre DGAC, ICTDEC, ESDEC e REDECs na produção e difusão","Definir critérios de priorização de municípios para adesão e capacitação","Monitorar o ciclo de produção e os resultados da adesão municipal"}', '{"Não produzir conteúdo (competência da DGAC e do ICTDEC)","Não executar na ponta (competência das REDECs)","Não conduzir capacitações (competência da ESDEC)"}', '{"Colaboração dos órgãos envolvidos na execução de suas partes","Informações das REDECs sobre necessidades e adesão municipal"}', '2026-02-21 12:05:31.311365+00'),
	(6, 2, 1, 'SUOP (sob aval da SUBSEGOP) — LÍDER COORDENADOR TRANSVERSAL', 'SUOP (sob aval da SUBSEGOP)', 'LÍDER COORDENADOR TRANSVERSAL', 'A ação impacta múltiplos setores, envolve priorização institucional e exige articulação entre técnica, orçamento e execução. Recursos captados precisam ser convertidos em projetos executáveis. Sem a SUOP coordenando, o ICTDEC capta mas não executa, a SUBSEGAD trata orçamento isoladamente e os órgãos finalísticos não alinham seus projetos. A SUOP é o ponto de convergência operacional. Com a perspectiva de operacionalização do Fundo Estadual, esse papel de coordenação se torna ainda mais crítico, pois a gestão do Fundo exigirá priorização centralizada e governança de portfólio em escala muito superior à atual.', '{"Definir prioridades institucionais para captação, com base no Plano Estratégico 2024–2035 e nas Ações Prioritárias de 2026","Validar as propostas técnicas elaboradas pelo ICTDEC e demais coexecutores antes da submissão","Articular setores para construção de propostas integradas, destravando gargalos de coordenação","Coordenar alocação estratégica dos recursos captados, garantindo coerência entre fonte e necessidade operacional","Integrar as iniciativas de captação ao portfólio de projetos da Secretaria (AE 2.1.2)","Supervisionar o Gabinete de Gestão de Projetos, assegurando sua operacionalidade e fortalecimento contínuo"}', '{"Não concentrar tecnicamente toda a elaboração de projetos (competência técnica do ICTDEC e demais órgãos)","Não transformar captação em iniciativa isolada de gabinete","Não permitir captação desconectada de capacidade de execução","Não delegar priorização sem definir critérios claros e transparentes"}', '{"Estrutura técnica de elaboração de projetos (ICTDEC)","Gabinete de Gestão de Projetos funcional e fortalecido","Informações orçamentárias e jurídicas atualizadas (SUBSEGAD e ASSEJUR)","Portfólio estruturado de projetos (AE 2.1.2)","Credibilidade institucional consolidada (AE 2.1.3)"}', '2026-02-21 12:05:31.311365+00'),
	(7, 2, 2, 'Gabinete de Gestão de Projetos — COEXECUTOR DE GESTÃO DE PORTFÓLIO', 'Gabinete de Gestão de Projetos', 'COEXECUTOR DE GESTÃO DE PORTFÓLIO', 'A captação de recursos é apenas o início do ciclo. Sem uma estrutura dedicada a gerir o portfólio de projetos — desde a concepção até o encerramento e prestação de contas —, os recursos captados correm risco de execução deficiente, atrasos e prejuízos institucionais.
