INSERT INTO "public"."fundamentacoes" ("id", "acao_estrategica_id", "introducao", "conclusao", "created_at") VALUES
	(1, 1, 'A ausência de um portfólio de projetos comunitários replicáveis gera três efeitos:', 'Esta ação enfrenta esses efeitos por meio de um ciclo de produção de portfólio: as REDECs coletam práticas nos municípios; a DGAC analisa, sistematiza e modela os projetos-prateleira (com suporte científico do ICTDEC/CEPEDEC quando necessário); a ESDEC capacita agentes para implementação; e as REDECs difundem o portfólio e articulam a adesão municipal. A SUOP valida e coordena o ciclo.', '2026-02-21 12:05:31.311365+00'),
	(2, 3, 'A ausência de gestão estratégica institucionalizada produz três efeitos operacionais diretos:', 'A institucionalização da gestão estratégica enfrenta esses três efeitos ao estabelecer dados estruturados para a tomada de decisão, ciclos de revisão que mantêm o Plano ativo e uma base objetiva e padronizada de avaliação. Trata-se da ação que confere sustentabilidade a todas as demais.', '2026-02-21 12:05:31.311365+00'),
	(3, 4, 'A ausência de gestão de projetos institucionalizada gera três efeitos operacionais diretos:', 'A institucionalização da gestão de projetos enfrenta esses efeitos ao estabelecer um método padronizado, uma estrutura dedicada (Gabinete) e ferramentas de acompanhamento, criando a capacidade institucional necessária para gerir o portfólio atual e absorver o crescimento futuro.', '2026-02-21 12:05:31.311365+00'),
	(4, 5, 'A ausência de instrumentos institucionais de transparência gera três efeitos operacionais diretos:', 'Esta ação enfrenta esses efeitos ao criar produtos padronizados de comunicação institucional que sistematizam as entregas, estruturam a prestação de contas e constroem credibilidade mensurável perante públicos internos e externos.', '2026-02-21 12:05:31.311365+00'),
	(5, 6, 'A ausência de ações estruturadas de fortalecimento cultural gera três efeitos operacionais:', 'Esta ação enfrenta esses efeitos ao promover ações contínuas de internalização dos valores e da Identidade Estratégica, integração transversal entre setores e institucionalização das condutas valorizadas, assegurando que a evolução cultural não dependa de indivíduos, mas se torne prática permanente da organização.', '2026-02-21 12:05:31.311365+00'),
	(6, 7, 'A ausência de revisão periódica das normas internas gera três efeitos operacionais:', 'Esta ação enfrenta esses efeitos ao instituir ciclos formais de revisão (previsibilidade), uma coletânea organizada do arcabouço normativo (acessibilidade) e Grupos de Trabalho com participação dos órgãos operadores (legitimidade e aplicabilidade das normas revisadas).', '2026-02-21 12:05:31.311365+00'),
	(7, 8, 'A ausência de gestão de processos institucionalizada gera três efeitos operacionais:', 'Esta ação enfrenta esses efeitos ao implantar uma metodologia padronizada de mapeamento (continuidade e impessoalidade), uma visão integrada pela Cadeia de Valor (conexão entre etapas) e um modelo de manutenção com repositório centralizado e atualização propositiva dos órgãos (escalabilidade com governança).', '2026-02-21 12:05:31.311365+00'),
	(8, 9, 'A ausência de gestão por competências gera três efeitos operacionais:', 'Esta ação enfrenta esses efeitos ao estabelecer um modelo integrado de mapeamento, diagnóstico e desenvolvimento que conecta funções a competências, competências a lacunas e lacunas a ações de capacitação, criando um ciclo contínuo de alinhamento entre capital humano e objetivos estratégicos.', '2026-02-21 12:05:31.311365+00'),
	(9, 10, 'A ausência de ações estruturadas de desenvolvimento do efetivo gera três efeitos operacionais:', 'Esta ação enfrenta esses efeitos ao estabelecer trilhas de educação continuada orientadas por diagnóstico (direção), estímulo ao autodesenvolvimento (protagonismo individual) e contratação de capacitações especializadas quando necessário (alcance), criando um sistema de desenvolvimento que é ao mesmo tempo institucional e contínuo.', '2026-02-21 12:05:31.311365+00'),
	(10, 11, 'A precariedade da infraestrutura física gera três efeitos operacionais:', 'Esta ação enfrenta esses efeitos ao instituir um fluxo estruturado de demanda, priorização e execução que conecta quem usa (Órgãos Subordinados), quem prioriza (SUOP) e quem apoia administrativamente (SUBSEGAD), substituindo a lógica reativa por planejamento.', '2026-02-21 12:05:31.311365+00'),
	(11, 12, 'A deficiência em sistemas tecnológicos gera três efeitos operacionais:', 'Esta ação enfrenta esses efeitos ao instituir um fluxo estruturado de demanda, priorização e coordenação que evita a fragmentação, um princípio de automação orientada por processo que evita investimento em soluções para problemas mal definidos, e a liderança setorial dos projetos de automação que garante que quem conhece o problema conduza a solução.', '2026-02-21 12:05:31.311365+00'),
	(12, 13, 'A gestão deficiente da rede de serviços contratados gera três efeitos operacionais:', 'Esta ação enfrenta esses efeitos ao instituir um fluxo de revisão periódica dos contratos vigentes (aderência), uma priorização estratégica das contratações (alinhamento) e o fortalecimento da fiscalização contratual pelos órgãos usuários (qualidade da execução).', '2026-02-21 12:05:31.311365+00'),
	(13, 14, 'A ausência de parcerias estruturadas de pesquisa e extensão gera três efeitos:', 'Esta ação enfrenta esses efeitos ao instituir parcerias orientadas por problema operacional (relevância), um ciclo estruturado de pesquisa com disseminação obrigatória (impacto) e a integração das demandas das COMDECs na agenda de pesquisa (coesão do Sistema).', '2026-02-21 12:05:31.311365+00'),
	(14, 15, 'A ausência de programas estruturados de extensão acadêmico-científica gera três efeitos:', 'Esta ação enfrenta esses efeitos ao criar programas estruturados de extensão orientados por demandas reais (relevância), com supervisão compartilhada entre CEPEDEC e IES (qualidade) e integração dos órgãos da Secretaria como campo de prática (aplicabilidade).', '2026-02-21 12:05:31.311365+00'),
	(15, 16, 'A ausência de integração a redes de pesquisa e ecossistemas de inovação gera três efeitos:', 'Esta ação enfrenta esses efeitos ao promover a inserção seletiva em redes relevantes (posicionamento), a participação ativa com contribuição técnica do CEPEDEC (legitimidade) e a orientação estratégica pela SUOP (relevância institucional).', '2026-02-21 12:05:31.311365+00'),
	(16, 17, 'A ausência de um ciclo estruturado de PD&I institucional gera três efeitos:', 'Esta ação enfrenta esses efeitos ao instituir um ciclo PD&I liderado pelo CEPEDEC (estrutura), alimentado pelos diagnósticos do ICTDEC (insumo) e orientado pelos problemas reais da operação (relevância), com incorporação das inovações coordenada pela SUOP (adoção).', '2026-02-21 12:05:31.311365+00'),
	(17, 18, 'A ausência de uma estratégia de gestão do conhecimento no âmbito do Sistema Estadual gera três efeitos:', 'Esta ação enfrenta esses efeitos ao instituir um fluxo de captura liderado pelas REDECs na ponta (alcance), validação científica pelo CEPEDEC (rigor) e devolução ao Sistema em formato de doutrina técnica (impacto).', '2026-02-21 12:05:31.311365+00'),
	(18, 19, 'A ausência de rotinas de sistematização do conhecimento interno gera três efeitos:', 'Esta ação enfrenta esses efeitos ao instituir um ciclo de três fases: criação conjunta de metodologias pelo ICTDEC e CEPEDEC (rigor + aplicabilidade), execução diferenciada conforme a natureza da atividade (ICTDEC nas dinâmicas transversais, órgãos nas aplicações setoriais) e análise e sistematização pelo CEPEDEC (transformação do material em base técnica institucional).', '2026-02-21 12:05:31.311365+00'),
	(19, 20, 'A ausência de uma política de preservação documental e memória técnica gera três efeitos:', 'Esta ação enfrenta esses efeitos ao instituir uma política de preservação liderada pelo ICTDEC (estrutura), alimentada pela produção científica do CEPEDEC e pelos registros dos órgãos (insumo), materializada numa publicação institucional periódica (visibilidade e blindagem).', '2026-02-21 12:05:31.311365+00'),
	(20, 21, 'A ausência de um mapeamento sistemático de inovações incrementais gera três efeitos:', 'Esta ação enfrenta esses efeitos ao instituir um identificação de pontos de melhoria pelo ICTDEC (visão de governança), busca de soluções pelo CEPEDEC (rigor técnico e articulação com parceiros) e validação pelos órgãos detentores dos processos (aplicabilidade).', '2026-02-21 12:05:31.311365+00'),
	(21, 22, 'A ausência de um mapeamento do ciclo da informação gera três efeitos:', 'Esta ação enfrenta esses efeitos ao instituir um mapeamento completo do ciclo da informação liderado pelo ICTDEC (visão de governança), alimentado pela descrição dos fluxos pelo CEPEDEC e pelos órgãos (realidade operacional), resultando em diretrizes e protocolos de fluxo informacional (governança aplicável).', '2026-02-21 12:05:31.311365+00'),
	(22, 23, 'A ausência de uma atuação parlamentar estruturada gera três efeitos:', 'Esta ação enfrenta esses efeitos ao estruturar uma atuação parlamentar municiada pelo suporte técnico do ICTDEC (fundamentação e panoramas de necessidade legislativa), executada pelo órgão responsável pela articulação com o Legislativo (estratégia no parlamento) e alimentada pelas demandas operacionais da SUOP e dos órgãos (realidade do campo).', '2026-02-21 12:05:31.311365+00'),
	(23, 24, 'A situação atual configura um problema estrutural grave, cujo agravamento é proporcional ao tempo de não-decisão:', 'Esta ação enfrenta esses problemas com um modelo de transição liderado pela SUBSEGOP (posicionamento político-institucional), coordenado pela SUOP (integração operacional), referenciado pelo CEMADEN-RJ (padrões técnicos), articulado pela DGDEC (relação com municípios), executado pelas REDECs (ponta), capacitado pela ESDEC (formação orçamentária e técnica) e complementado pela DGAC (conscientização).', '2026-02-21 12:05:31.311365+00'),
	(24, 25, 'A cooperação do Estado com os municípios em prevenção e mitigação enfrenta três obstáculos estruturais:', 'Esta ação enfrenta esses obstáculos instituindo um regime de cooperação multifacetado coordenado pela SUOP, que integra as competências dos órgãos da Defesa Civil Estadual numa oferta coerente de apoio aos municípios — combinando alertas e panoramas de risco (CEMADEN-RJ), engenharia e articulação para obras (Coord. Engenharia), meio ambiente (CEAMA), conhecimento científico e orientação no mapeamento (ICTDEC/CEPEDEC), capacitação (ESDEC), conscientização (DGAC) e execução territorial (REDECs via DREDEC).', '2026-02-21 12:05:31.311365+00'),
	(25, 26, 'A ausência de conteúdo doutrinário atualizado gera três efeitos:', 'Esta ação enfrenta esses efeitos instituindo um ciclo de produção doutrinária liderado pelo ICTDEC (sistematização via CEPEDEC, difusão via ESDEC), alimentado pelos órgãos operacionais (DGDEC, CESTAD e REDECs como fontes de conhecimento) e validado pela SUOP (alinhamento estratégico e aplicabilidade).', '2026-02-21 12:05:31.311365+00'),
	(26, 27, 'A colaboração do Estado com os municípios em preparação e resposta enfrenta três obstáculos:', 'Esta ação enfrenta esses obstáculos instituindo um regime de colaboração em duas dimensões coordenado pela SUOP: preparação (assessoria ao planejamento de contingência, capacitação e exercícios simulados) e resposta (mobilização coordenada de suporte operacional quando a capacidade municipal for excedida), com a DGDEC como eixo operacional, o CESTAD na coordenação de crises, o CEMADEN-RJ nos alertas, o GRAC na integração multisetorial, a ESDEC na capacitação e as REDECs na execução territorial.', '2026-02-21 12:05:31.311365+00'),
	(27, 28, 'A articulação do aparato estatal para recuperação pós-desastre enfrenta três obstáculos:', 'Esta ação enfrenta esses obstáculos instituindo um fluxo normatizado de recebimento, avaliação, priorização e articulação: as REDECs e a DGDEC recebem e consolidam as demandas; a Coordenadoria de Engenharia avalia a infraestrutura; a SUOP define a priorização com critérios técnicos; e o GRAC mobiliza os órgãos estaduais competentes para a execução.', '2026-02-21 12:05:31.311365+00'),
	(28, 29, 'A ausência de conscientização dos órgãos estaduais sobre os princípios de reconstrução resiliente gera três efeitos:', 'Esta ação enfrenta esses efeitos por meio de uma estratégia de influência técnico-institucional: o ICTDEC produz as diretrizes de reconstrução resiliente com suporte técnico da Coordenadoria de Engenharia; a SUOP valida e coordena internamente; e a SUBSEGOP articula o acesso político-institucional aos órgãos estaduais executores, viabilizando a difusão efetiva.', '2026-02-21 12:05:31.311365+00'),
	(29, 30, 'A ausência de mecanismos de discussão intersetorial sobre RRD gera três efeitos:', 'Esta ação enfrenta esses efeitos por meio de uma estratégia de articulação intersetorial ampliada: a SUBSEGOP conduz o diálogo político-institucional com os órgãos estaduais e atores externos; o ICTDEC fornece o conteúdo técnico que qualifica as discussões; a ESDEC capacita agentes; a DGAC e a CEAMA contribuem com seus temas setoriais; as REDECs articulam a participação municipal; e o CONEPDEC, como conselho multiparticipativo, valida as propostas e confere legitimidade multisetorial. A SUOP coordena internamente a participação dos órgãos da SEDEC.', '2026-02-21 12:05:31.311365+00'),
	(30, 2, 'A Secretaria de Estado de Defesa Civil opera historicamente com dependência quase total do Tesouro Estadual. Isso gera problemas concretos que afetam o dia a dia:', 'Esta ação estratégica ataca esses quatro problemas simultaneamente: ao estruturar a capacidade de captação, fortalecer o Gabinete de Gestão de Projetos e preparar a governança financeira, cria-se tanto uma segunda linha de financiamento imediata (editais e parcerias) quanto o alicerce para o Fundo Estadual. Simultaneamente, o processo força a profissionalização interna — elaborar projetos exige diagnóstico, dados e governança, que é exatamente o que o Programa SEDEC 360 busca implantar.', '2026-02-21 12:05:31.311365+00');
INSERT INTO "public"."fundamentacao_itens" ("id", "fundamentacao_id", "ordem", "conteudo", "created_at") VALUES
	(1, 1, 1, '1. Barreira de entrada: Municípios que desejam implementar projetos de proteção comunitária não dispõem de modelos, metodologias ou materiais de referência. O custo de criação do zero é alto e a maioria das COMDECs não tem capacidade técnica para desenvolver projetos próprios. O resultado é que a implementação não ocorre ou depende de iniciativas individuais.', '2026-02-21 12:05:31.311365+00'),
	(2, 1, 2, '2. Disparidade entre municípios: Sem padronização, a qualidade das iniciativas comunitárias varia conforme a capacidade de cada gestão municipal. Municípios com mais recursos produzem projetos melhores; municípios vulneráveis ficam sem cobertura. A percepção de risco e a conscientização comunitária ficam desiguais no território estadual.', '2026-02-21 12:05:31.311365+00'),
	(3, 1, 3, '3. Práticas exitosas não sistematizadas: Municípios que desenvolveram projetos comunitários bem-sucedidos não têm canal para compartilhar suas práticas. O conhecimento gerado fica restrito ao município de origem, sem gerar benefício para o restante do Estado.', '2026-02-21 12:05:31.311365+00'),
	(4, 2, 1, '1. Ausência de visibilidade sobre o desempenho: Sem rotinas de monitoramento, não há como aferir objetivamente quais setores estão entregando conforme o planejado, quais enfrentam gargalos e quais necessitam de suporte. A gestão opera sem dados estruturados, apoiando-se predominantemente em percepções informais.', '2026-02-21 12:05:31.311365+00'),
	(5, 2, 2, '2. Risco de descontinuidade do Plano Estratégico: Um planejamento estratégico que não é acompanhado por rotinas visíveis e periódicas tende a perder relevância institucional progressivamente. Isso compromete a adesão dos gestores e reduz a capacidade da Secretaria de sustentar políticas de longo prazo.', '2026-02-21 12:05:31.311365+00'),
	(6, 2, 3, '3. Cobrança sem base objetiva: Na ausência de indicadores padronizados, a avaliação de desempenho dos setores fica dependente de critérios informais e variáveis, o que dificulta a responsabilização equitativa e a identificação precisa dos pontos de melhoria.', '2026-02-21 12:05:31.311365+00'),
	(7, 3, 1, '1. Fragmentação de métodos: Cada setor adota seus próprios critérios de planejamento, execução e acompanhamento de projetos. Isso impede a consolidação de um portfólio institucional e dificulta a visão integrada de prazos, custos e entregas.', '2026-02-21 12:05:31.311365+00'),
	(8, 3, 2, '2. Risco na execução de recursos externos: Projetos financiados por editais, convênios ou fundos exigem acompanhamento rigoroso da execução físico-financeira e prestação de contas tempestiva. Sem instrumento padronizado, a Secretaria fica exposta a riscos de inadimplência e devolução de recursos.', '2026-02-21 12:05:31.311365+00'),
	(9, 3, 3, '3. Perda de capacidade de escala: A operacionalização do Fundo Estadual de Proteção e Defesa Civil exigirá gestão simultânea de dezenas de projetos, incluindo repasses a municípios. Essa escala é inviável sem estrutura, metodologia e ferramentas adequadas.', '2026-02-21 12:05:31.311365+00'),
	(10, 4, 1, '1. Invisibilidade das entregas: A Secretaria realiza um volume significativo de ações que não são sistematizadas nem comunicadas de forma estruturada. Isso produz uma percepção distorcida tanto interna (setores desconhecem o que os demais fazem) quanto externa (financiadores, parceiros e sociedade não têm acesso ao escopo real de atuação da Defesa Civil).', '2026-02-21 12:05:31.311365+00'),
	(11, 4, 2, '2. Fragilidade na prestação de contas: Sem relatório de gestão institucionalizado, a Secretaria depende de compilações improvisadas para responder a demandas de órgãos de controle, legislativo ou imprensa. Isso consome tempo, gera inconsistências e expõe a instituição a riscos reputacionais.', '2026-02-21 12:05:31.311365+00'),
	(12, 4, 3, '3. Perda de credibilidade para captação: A atração de investimentos e parcerias (AE 1.1.3) depende da capacidade de demonstrar resultados. Agências de fomento, organismos internacionais e potenciais parceiros avaliam a maturidade institucional também pela qualidade dos instrumentos de comunicação. Sem eles, a Secretaria compete em desvantagem.', '2026-02-21 12:05:31.311365+00'),
	(13, 5, 1, '1. Baixa adesão a novos instrumentos de gestão: A implantação de metodologias de gestão estratégica, processos, projetos e competências exige mudança de hábitos e rotinas. Sem um trabalho deliberado de preparação cultural, essas mudanças enfrentam resistência passiva e tendem a se esvaziar após o impulso inicial de implantação.', '2026-02-21 12:05:31.311365+00'),
	(14, 5, 2, '2. Fragmentação entre setores: A Secretaria é composta por órgãos com missões distintas, distribuídos em diferentes localidades e com dinâmicas operacionais próprias. Sem ações de integração transversal, cada setor tende a operar de forma isolada, com baixo conhecimento sobre as atividades dos demais, o que dificulta a coordenação e a sinergia.', '2026-02-21 12:05:31.311365+00'),
	(15, 5, 3, '3. Descontinuidade de boas práticas: Quando os valores e as condutas não são formalizados e internalizados, as boas práticas dependem das pessoas que as praticam. A rotatividade de pessoal, natural em órgãos públicos, leva à perda de práticas positivas não institucionalizadas.', '2026-02-21 12:05:31.311365+00'),
	(16, 6, 1, '1. Insegurança jurídica na tomada de decisão: Gestores que atuam sob normas desatualizadas enfrentam ambiguidade sobre o que é permitido, esperado ou vedado. Isso leva a duas reações igualmente danosas: paralisia decisória (medo de agir sem respaldo) ou ação sem padronização (cada gestor interpreta a norma à sua maneira).', '2026-02-21 12:05:31.311365+00'),
	(17, 6, 2, '2. Despadronização de condutas: Quando as normas não acompanham a evolução da legislação e da prática operacional, os setores desenvolvem soluções informais próprias. O resultado é a fragmentação: o mesmo procedimento é executado de formas diferentes por órgãos distintos, comprometendo a rastreabilidade e a uniformidade.', '2026-02-21 12:05:31.311365+00'),
	(18, 6, 3, '3. Normas inacessíveis ou desconhecidas: Sem uma coletânea organizada e atualizada, os servidores frequentemente desconhecem quais normas estão vigentes ou onde encontrá-las. A dispersão documental agrava o problema, pois normas publicadas em períodos distintos e em diferentes veículos se acumulam sem consolidação.', '2026-02-21 12:05:31.311365+00'),
	(19, 7, 1, '1. Dependência de conhecimento individual: Quando os processos não estão mapeados e padronizados, a execução depende de quem sabe fazer. A rotatividade de pessoal, natural em órgãos públicos, gera perda de capacidade operacional a cada movimentação, pois o conhecimento sai com a pessoa.', '2026-02-21 12:05:31.311365+00'),
	(20, 7, 2, '2. Desconexão entre setores: Processos finalísticos frequentemente envolvem múltiplos órgãos. Sem a visão integrada da cadeia de valor, cada setor otimiza apenas a sua etapa, gerando descompassos nas interfaces: um setor entrega fora do formato que o próximo precisa, prazos não se conectam, retrabalho se acumula.', '2026-02-21 12:05:31.311365+00'),
	(21, 7, 3, '3. Impossibilidade de melhoria sistemática: Sem processos mapeados, não há base para identificar gargalos, medir eficiência ou propor otimizações. As melhorias acontecem de forma intuitiva e localizada, sem escala nem rastreabilidade.', '2026-02-21 12:05:31.311365+00'),
	(22, 8, 1, '1. Alocação desconectada da necessidade: Sem o conhecimento sistemático de quais competências cada função exige e quais a força de trabalho possui, a alocação de pessoal depende de critérios informais. Pessoas são designadas para funções sem que se verifique a aderência entre suas competências e as demandas da posição.', '2026-02-21 12:05:31.311365+00'),
	(23, 8, 2, '2. Capacitação sem foco estratégico: Sem diagnóstico de lacunas, as capacitações são orientadas por demandas avulsas ou por disponibilidade de oferta, e não pelas necessidades reais da instituição. Isso gera investimento em desenvolvimento que não necessariamente se traduz em melhoria de desempenho.', '2026-02-21 12:05:31.311365+00'),
	(24, 8, 3, '3. Ausência de referência para desenvolvimento: Sem um modelo que defina o que se espera de cada função, os servidores não têm clareza sobre quais competências devem desenvolver. O crescimento profissional fica sem direção institucional, dependendo exclusivamente de iniciativa individual.', '2026-02-21 12:05:31.311365+00'),
	(25, 9, 1, '1. Defasagem técnica progressiva: A gestão de riscos e desastres é um campo em evolução permanente — novas metodologias, tecnologias e marcos legais surgem continuamente. Sem educação continuada, o efetivo opera com base em conhecimentos desatualizados, comprometendo a qualidade técnica das ações de prevenção, preparação e resposta.', '2026-02-21 12:05:31.311365+00'),
	(26, 9, 2, '2. Concentração de expertise em poucos indivíduos: Sem mecanismos de difusão do conhecimento, a expertise técnica tende a se concentrar em um número reduzido de profissionais. Isso cria vulnerabilidade institucional: a ausência ou movimentação dessas pessoas gera perda de capacidade operacional desproporcional.', '2026-02-21 12:05:31.311365+00'),
	(27, 9, 3, '3. Capacitação reativa e sem direção: Na ausência de trilhas estruturadas, as capacitações ocorrem de forma avulsa, orientadas por oportunidades pontuais ou por iniciativa individual. O investimento em desenvolvimento não se traduz necessariamente em melhoria da capacidade institucional, pois não é orientado pelas lacunas reais.', '2026-02-21 12:05:31.311365+00'),
	(28, 10, 1, '1. Perda de produtividade e qualidade de vida no trabalho: Instalações inadequadas (espaço insuficiente, falta de ergonomia, problemas de salubridade) afetam diretamente a capacidade de trabalho das equipes. O impacto não é apenas físico: ambientes precários corroem a motivação e reforçam a percepção de desvalorização institucional.', '2026-02-21 12:05:31.311365+00'),
	(29, 10, 2, '2. Limitação da capacidade operacional: A ausência de espaços adequados impede a realização de atividades que a estratégia prevê: salas para oficinas de mapeamento de processos, espaços para capacitações presenciais, condições de armazenamento para equipamentos operacionais. A infraestrutura precária se torna gargalo para ações de outras AEs.', '2026-02-21 12:05:31.311365+00'),
	(30, 10, 3, '3. Intervenções reativas e fragmentadas: Sem um processo estruturado de identificação, priorização e execução, as melhorias de infraestrutura acontecem apenas quando a precariedade atinge nível crítico, em caráter emergencial, com custo mais alto e menor qualidade.', '2026-02-21 12:05:31.311365+00'),
	(31, 11, 1, '1. Controles manuais excessivos e retrabalho: Sem ferramentas adequadas, as equipes dependem de planilhas manuais, controles paralelos e trocas informais de informação. Isso gera retrabalho, erros de consolidação e perda de tempo em atividades que poderiam ser automatizadas ou simplificadas.', '2026-02-21 12:05:31.311365+00'),
	(32, 11, 2, '2. Fragmentação da infraestrutura digital: Quando cada órgão adota soluções por conta própria, sem padronização, geram-se sistemas que não se comunicam, dados duplicados e dificuldade de consolidação de informações para a gestão.', '2026-02-21 12:05:31.311365+00'),
	(33, 11, 3, '3. Gargalos de capacidade que limitam a estratégia: A ausência de sistemas adequados impede que ações de outras AEs atinjam pleno potencial: indicadores sem sistema de coleta automatizada, processos mapeados sem plataforma de registro, capacitações sem plataforma EAD. A deficiência tecnológica se torna gargalo transversal.', '2026-02-21 12:05:31.311365+00'),
	(34, 12, 1, '1. Contratos desalinhados com a necessidade real: Quando os contratos são renovados sem revisão crítica, perpetuam-se serviços que não correspondem mais às demandas atuais. A Secretaria paga por serviços subutilizados enquanto áreas críticas permanecem desassistidas.', '2026-02-21 12:05:31.311365+00'),
	(35, 12, 2, '2. Fragilidade na prontidão operacional: A defesa civil opera em dois regimes — normalidade e crise. Contratos que atendem apenas à rotina administrativa podem ser insuficientes nos picos de demanda gerados por desastres. Sem planejamento estratégico do portfólio, a Secretaria fica vulnerável nos momentos de maior exigência.', '2026-02-21 12:05:31.311365+00'),
	(36, 12, 3, '3. Lentidão e baixa qualidade na instrução: Processos de contratação mal instruídos geram atrasos, impugnações e contratos com especificações insuficientes. O resultado é um ciclo de retrabalho que consome tempo administrativo e compromete a qualidade do serviço prestado.', '2026-02-21 12:05:31.311365+00'),
	(37, 13, 1, '1. Atuação baseada em empirismo: Sem pesquisa aplicada, as práticas da Defesa Civil se baseiam na experiência acumulada e na repetição de procedimentos históricos, sem validação científica ou comparação com as melhores práticas. A evolução fica limitada ao que se aprende na prática, sem aporte sistemático de conhecimento novo.', '2026-02-21 12:05:31.311365+00'),
	(38, 13, 2, '2. Desconexão entre academia e operação: Quando existem, as parcerias acadêmicas tendem a ser pontuais, orientadas pelo interesse do pesquisador e não pelo problema da instituição. A produção científica gerada não se traduz em melhoria de práticas, protocolos ou políticas — fica restrita a publicações que não chegam à ponta.', '2026-02-21 12:05:31.311365+00'),
	(39, 13, 3, '3. Isolamento dos municípios: As COMDECs enfrentam gargalos operacionais específicos que a estrutura estadual muitas vezes desconhece. Sem mecanismo de integração para pesquisa e extensão, os municípios permanecem isolados na busca de soluções, e a Secretaria perde a oportunidade de produzir conhecimento que beneficie todo o Sistema.', '2026-02-21 12:05:31.311365+00'),
	(40, 14, 1, '1. Isolamento institucional: Sem conexão sistemática com a academia, a Secretaria opera em circuito fechado. Não recebe olhar externo, não é desafiada por questões novas e não incorpora métodos e conhecimentos produzidos fora de suas fronteiras. A tendência é a repetição de práticas sem renovação.', '2026-02-21 12:05:31.311365+00'),
	(41, 14, 2, '2. Formação desconectada da realidade: Do lado acadêmico, os futuros profissionais de gestão de riscos e desastres se formam sem contato com a realidade operacional da Defesa Civil. Quando ingressam no serviço público, enfrentam um choque entre teoria e prática que poderia ter sido atenuado por uma experiência de extensão supervisionada.', '2026-02-21 12:05:31.311365+00'),
	(42, 14, 3, '3. Desperdício de potencial: Gargalos operacionais que poderiam ser endereçados por estudantes e pesquisadores permanecem sem solução porque não há mecanismo institucional para conectar a demanda à oferta acadêmica. A Secretaria não se beneficia de uma força de trabalho qualificada e motivada que está disponível nas IES.', '2026-02-21 12:05:31.311365+00'),
	(43, 15, 1, '1. Invisibilidade científica: A Defesa Civil do Estado não é percebida como ator científico pelos centros de pesquisa, agências de fomento e organismos internacionais. Isso significa menor acesso a editais, menor atração de parceiros qualificados e menor influência na construção de políticas baseadas em evidência.', '2026-02-21 12:05:31.311365+00'),
	(44, 15, 2, '2. Duplicação de esforços: Sem participação em redes, a Secretaria pode investir em pesquisas que já foram conduzidas por outros órgãos de defesa civil, no Brasil ou no exterior. A integração em rede permite compartilhar resultados, evitar replicação e construir sobre o conhecimento já existente.', '2026-02-21 12:05:31.311365+00'),
	(45, 15, 3, '3. Limitação do alcance: Problemas complexos como a redução de riscos de desastres demandam abordagens multi-institucionais e multidisciplinares. Uma instituição isolada não tem escala, diversidade de competências nem base de dados suficiente para enfrentar esses problemas. Redes ampliam o alcance sem exigir que cada instituição detenha todas as capacidades internamente.', '2026-02-21 12:05:31.311365+00'),
	(46, 16, 1, '1. Repetição de práticas obsoletas: Sem mecanismo para transformar diagnósticos em soluções, os problemas identificados nas ações de governança permanecem como diagnósticos — conhecidos, documentados, mas não resolvidos. A instituição sabe o que está errado, mas não tem mecanismo para criar o que está certo.', '2026-02-21 12:05:31.311365+00'),
	(47, 16, 2, '2. Inovação espontânea e não institucionalizada: Na ausência de PD&I estruturado, inovações acontecem de forma espontânea e personalista — dependem da iniciativa individual e não são registradas, validadas ou replicadas. Quando a pessoa sai, a inovação se perde.', '2026-02-21 12:05:31.311365+00'),
	(48, 16, 3, '3. Desconexão entre diagnóstico e solução: As ações de governança (OE 2) geram um volume crescente de informações sobre gargalos e oportunidades. Sem o ciclo PD&I, esses insumos não se transformam em produtos concretos — a Secretaria diagnostica cada vez melhor, mas não traduz o diagnóstico em melhoria.', '2026-02-21 12:05:31.311365+00'),
	(49, 17, 1, '1. Perda de capital intelectual: Soluções criativas desenvolvidas nos municípios nunca são registradas. Quando o agente se aposenta, é transferido ou deixa o cargo, o conhecimento se perde irremediavelmente. A Defesa Civil reinventa a roda em cada crise, em cada município, sem acumular aprendizado.', '2026-02-21 12:05:31.311365+00'),
	(50, 17, 2, '2. Invisibilidade científica das práticas locais: Os municípios produzem ações relevantes de defesa civil que não ganham visibilidade porque não são documentadas com rigor. O Estado do Rio de Janeiro possui um acervo potencial de boas práticas que permanece invisível — tanto para o próprio Sistema quanto para a comunidade científica e os órgãos de fomento.', '2026-02-21 12:05:31.311365+00'),
	(51, 17, 3, '3. Fragmentação do Sistema: Sem mecanismo de intercâmbio de saberes, cada município opera isoladamente. Problemas semelhantes são enfrentados de formas diferentes, sem que uma solução bem-sucedida em um local possa ser adaptada para outro. A coesão do SIEPDEC depende também de uma base de conhecimento compartilhada.', '2026-02-21 12:05:31.311365+00'),
	(52, 18, 1, '1. Dependência de pessoas, não de processos: O conhecimento operacional crítico reside na memória individual. Transferências, aposentadorias e desligamentos geram perda irrecuperável de saber acumulado. A instituição não herda o que seus agentes aprenderam — apenas recomeça.', '2026-02-21 12:05:31.311365+00'),
	(53, 18, 2, '2. Lições não aprendidas: Após desastres e exercícios simulados, a análise do que funcionou e do que falhou é feita informalmente e se dissipa em dias. Sem painéis estruturados e registro sistemático, os mesmos erros se repetem e as melhores práticas não se disseminam.', '2026-02-21 12:05:31.311365+00'),
	(54, 18, 3, '3. Base de inovação empírica vazia: A AE 6.2.1 (PD&I institucional) depende de insumos sobre problemas e práticas reais. Sem a sistematização do conhecimento tácito, o ciclo PD&I opera sem matéria-prima — a inovação se desconecta da realidade operacional porque não tem acesso estruturado a ela.', '2026-02-21 12:05:31.311365+00'),
	(55, 19, 1, '1. Amnésia institucional: Sem registro organizado, a Secretaria não consegue demonstrar o que fez, como evoluiu nem por que tomou determinadas decisões. Cada gestão começa do zero, sem acesso ao histórico das anteriores. A rastreabilidade das evoluções doutrinárias é inexistente.', '2026-02-21 12:05:31.311365+00'),
	(56, 19, 2, '2. Produção científica sem preservação: O CEPEDEC produz pesquisas, o ICTDEC sistematiza conhecimento, os órgãos geram relatórios. Sem acervo organizado, esses produtos se dispersam em pastas pessoais, e-mails e pen drives — vulneráveis a perda, duplicação e obsolescência. O investimento em produção de conhecimento se perde.', '2026-02-21 12:05:31.311365+00'),
	(57, 19, 3, '3. Vulnerabilidade institucional: Uma instituição que não documenta suas ações fica exposta a questionámentos sem capacidade de resposta. A memória técnica organizada é blindagem: comprova o que foi feito, por quem, quando e com qual fundamentação.', '2026-02-21 12:05:31.311365+00'),
	(58, 20, 1, '1. Soluções congeladas no tempo: Produtos, processos e serviços permanecem como foram criados, sem incorporar melhorias disponíveis. A Secretaria opera com ferramentas que poderiam ser atualizadas, mas não tem mecanismo para identificar e aplicar essas atualizações de forma sistemática.', '2026-02-21 12:05:31.311365+00'),
	(59, 20, 2, '2. Conhecimento produzido sem aplicação: As ações de PD&I e de sistematização de conhecimento geram produtos valiosos, mas sem um mecanismo de transferência para a operação, esse conhecimento não se traduz em melhoria concreta. A Secretaria investe em pesquisa e não colhe os frutos.', '2026-02-21 12:05:31.311365+00'),
	(60, 20, 3, '3. Substituição total como única via de mudança: Sem cultura de melhoria incremental, a única forma percebida de mudar é substituir tudo. Isso eleva custos, gera resistência e paralisa a inovação. A melhoria incremental é mais ágil, menos custosa e menos disruptiva.', '2026-02-21 12:05:31.311365+00'),
	(61, 21, 1, '1. Dados dispersos e inacessíveis: A informação produzida pela Secretaria está espalhada em sistemas, pastas pessoais, e-mails e pen drives. Sem mapeamento, não se sabe o que existe, onde está nem quem é responsável. A mesma informação é produzida em duplicidade por setores diferentes, enquanto outras informações críticas não são produzidas por ninguém.', '2026-02-21 12:05:31.311365+00'),
	(62, 21, 2, '2. Decisões com informação incompleta: Gestores tomam decisões sem acesso à informação disponível porque não há fluxo de disseminação definido. A informação existe, mas não chega a quem precisa dela. O resultado é “achismo” em lugar de decisão fundamentada.', '2026-02-21 12:05:31.311365+00'),
	(63, 21, 3, '3. Memória técnica sem base informacional: As ações de preservação documental (AE 6.3.3) e de construção de repositórios (AE 6.5.2) dependem de saber o que existe e onde está. Sem o mapeamento do ciclo, essas ações operam no escuro.', '2026-02-21 12:05:31.311365+00'),
	(64, 22, 1, '1. Invisibilidade legislativa: A agenda de Gestão de Riscos e Desastres não é protagonista nas discussões orçamentárias e normativas. Sem presença ativa no Legislativo, a Defesa Civil compete por recursos em desigualdade com agendas politicamente mais visíveis. Emendas orçamentárias e proposições legislativas favoráveis dependem de oportunismo, não de estratégia.', '2026-02-21 12:05:31.311365+00'),
	(65, 22, 2, '2. Vulnerabilidade normativa: Projetos de lei que impactam a Defesa Civil — cortes orçamentários, alterações de competência, regulamentações inadequadas — tramitam sem que a Secretaria tenha voz qualificada para reagir. A ausência de assessoria parlamentar técnica deixa a pasta exposta a decisões legislativas tomadas sem compreensão da especificidade da GRD.', '2026-02-21 12:05:31.311365+00'),
	(66, 22, 3, '3. Articulação dependente de pessoas: Quando a atuação parlamentar ocorre, tende a ser reativa e baseada em relações pessoais, não em argumentação técnica institucional. A eficácia da articulação depende de quem a conduz, não da qualidade do argumento nem do alinhamento estratégico. A saída de uma pessoa pode desmontar toda a articulação.', '2026-02-21 12:05:31.311365+00'),
	(67, 23, 1, '1. Inversão de competências com custo crescente: O Estado mantém sistemas de alarme por sirenes que são competência municipal (Art. 8º, V-B da Lei 12.608/2012). Cada ano de manutenção estadual aprofunda o comprometimento orçamentário da SEDEC, reduzindo a capacidade de investimento nas competências que são efetivamente do Estado: monitoramento meteorológico, hidrológico e geológico, emissão de alertas e cobertura tecnológica. A perda de capacidade orçamentária não é hipotética — já é realidade: o CEMADEN-RJ tem carência de investimento em instrumentos e tecnologias de monitoramento precisamente porque os recursos foram direcionados ao sistema de sirenes municipal.', '2026-02-21 12:05:31.311365+00'),
	(68, 23, 2, '2. Dependência municipal institucionalizada: Os municípios que receberam sistemas implantados pelo Estado não desenvolveram capacidade técnica para operá-los, não elaboraram ETP e TR para contratação de manutenção e não ajustaram seus orçamentos para absorver essa despesa. A dependência não é acidental — é o resultado previsível de um modelo que implanta sem transferir capacidade. Quando o Estado reduz o suporte, os sistemas se degradam e a população fica desprotegida.', '2026-02-21 12:05:31.311365+00'),
	(69, 23, 3, '3. Exposição a questionamentos dos órgãos de controle: A SEDEC gasta recursos orçamentários em competência que não é sua. Essa situação configura risco de questionamento por órgãos de controle externo (TCE, MP) — tanto pela execução de despesa fora de competência quanto pela possível omissão nas competências próprias. A não-decisão não elimina o risco — apenas atrasa o questionamento e agrava suas consequências.', '2026-02-21 12:05:31.311365+00'),
	(70, 23, 4, '4. Comunidades sem preparação: Mesmo onde os sistemas existem, a população muitas vezes não sabe o que os sinais significam nem como reagir. Sistemas de alarme sem conscientização comunitária e sem simulados regulares são infraestrutura ociosa — e a responsabilidade por qualquer falha de resposta recai sobre o Estado. Nota sobre Posicionamento Institucional e Risco de Omissão', '2026-02-21 12:05:31.311365+00'),
	(71, 24, 1, '1. Municípios sem capacidade técnica: A maioria dos municípios fluminenses não dispõe de corpo técnico qualificado para conduzir mapeamentos de risco, elaborar planos de prevenção ou especificar medidas estruturais. Sem suporte estadual, as ações de prevenção e mitigação simplesmente não acontecem.', '2026-02-21 12:05:31.311365+00'),
	(72, 24, 2, '2. Cooperação fragmentada: Quando o Estado atua, tende a fazê-lo de forma setorial e descoordenada: o CEMADEN-RJ emite alertas, a Coordenadoria de Engenharia opina sobre obras, a ESDEC capacita, a DGAC conscientiza — cada um no seu tempo, sem integração. O município recebe ações avulsas que não se somam num regime coerente de prevenção.', '2026-02-21 12:05:31.311365+00'),
	(73, 24, 3, '3. Ações reativas, não preventivas: A cultura institucional privilegia a resposta a desastres sobre a prevenção. Os municípios buscam o Estado após o desastre, não antes. A cooperação preventiva exige mudança de postura: antecipar-se ao evento, não reagir a ele.', '2026-02-21 12:05:31.311365+00'),
	(74, 25, 1, '1. Conhecimento preso em pessoas: A Secretaria depende da memória e da experiência de indivíduos para executar suas ações de preparação e resposta. Quando essas pessoas são transferidas, promovidas ou se aposentam, o conhecimento não permanece na instituição. A rotatividade — particularmente alta nas REDECs — amplifica esse efeito, gerando perda recorrente de capacidade operacional.', '2026-02-21 12:05:31.311365+00'),
	(75, 25, 2, '2. Padronização inexistente: Sem manuais e POPs, cada equipe opera conforme sua própria interpretação. A mesma situação é tratada de formas diferentes por equipes diferentes. Isso gera inconsistência na resposta, dificulta a coordenação e impõe risco à população atendida.', '2026-02-21 12:05:31.311365+00'),
	(76, 25, 3, '3. Capacitação sem base doutrinária: A ESDEC forma agentes sem ter manuais de referência consolidados. O conteúdo da capacitação depende de quem ministra, não de uma doutrina institucional. Isso reproduz, na formação, o mesmo personalismo que afeta a operação.', '2026-02-21 12:05:31.311365+00'),
	(77, 26, 1, '1. Preparação insuficiente: A maioria dos municípios fluminenses não dispõe de planos de contingência atualizados, não realiza exercícios simulados regulares e não tem agentes capacitados para coordenar a resposta a desastres. Quando o evento ocorre, a resposta local é improvisada e a demanda por suporte estadual chega sem planejamento prévio.', '2026-02-21 12:05:31.311365+00'),
	(78, 26, 2, '2. Resposta desarticulada: A mobilização do suporte estadual em situação de crise envolve múltiplos órgãos (DGDEC, CESTAD, CEMADEN-RJ, GRAC, REDECs). Sem coordenação prévia e protocolos definidos, a atuação é fragmentada: cada órgão atua no seu tempo, com seus fluxos, gerando sobreposição de esforços em alguns pontos e lacunas em outros.', '2026-02-21 12:05:31.311365+00'),
	(79, 26, 3, '3. Dependência crônica do Estado: Municípios que não investem em preparação tornam-se cronicamente dependentes do suporte estadual durante desastres. Isso sobrecarrega os recursos do Estado e reduz a capacidade de atendimento simultâneo a múltiplos municípios afetados.', '2026-02-21 12:05:31.311365+00'),
	(80, 27, 1, '1. Ausência de fluxo normatizado: Não há procedimento padronizado para que os municípios solicitem apoio à recuperação e para que a SEDEC receba, avalie e encaminhe essas demandas. As solicitações chegam por canais informais, sem documentação técnica adequada e sem critérios de priorização.', '2026-02-21 12:05:31.311365+00'),
	(81, 27, 2, '2. Priorização política em vez de técnica: Sem avaliações de danos auditáveis e critérios técnicos definidos, a priorização das demandas de recuperação tende a ser política. Municípios com maior articulação política recebem atenção antes de municípios com maior necessidade técnica. Isso compromete a efetividade dos recursos do Estado e gera questionamentos dos órgãos de controle.', '2026-02-21 12:05:31.311365+00'),
	(82, 27, 3, '3. Desconexão entre SEDEC e órgãos executores: A SEDEC identifica a necessidade de recuperação, mas não tem fluxo estabelecido para acionar os órgãos estaduais que executam as obras e intervenções. Sem o GRAC como instância articuladora, a comunicação com os órgãos setoriais é ad hoc e depende de relações pessoais.', '2026-02-21 12:05:31.311365+00'),
	(83, 28, 1, '1. Reprodução de vulnerabilidades: Os órgãos estaduais que executam a recuperação tendem a reconstruir a infraestrutura no mesmo padrão anterior ao desastre, sem incorporar medidas de redução de risco. O resultado é que a próxima ocorrência produzirá os mesmos danos, gerando um ciclo de reconstrução sem ganho de resiliência.', '2026-02-21 12:05:31.311365+00'),
	(84, 28, 2, '2. Desperdício de recursos públicos: Reconstruir sem resiliência é reconstruir para destruir de novo. Os investimentos públicos em recuperação perdem efetividade quando não incorporam princípios de redução de risco, gerando despesa recorrente com as mesmas infraestruturas.', '2026-02-21 12:05:31.311365+00'),
	(85, 28, 3, '3. Desconexão entre Defesa Civil e órgãos executores: A SEDEC identifica as vulnerabilidades e conhece os riscos, mas não tem canal estabelecido para influenciar tecnicamente os projetos de recuperação executados por outros órgãos. O conhecimento acumulado pela Defesa Civil sobre os riscos do território não chega a quem decide sobre a reconstrução.', '2026-02-21 12:05:31.311365+00'),
	(86, 29, 1, '1. RRD como tema setorial: A redução de riscos de desastres é tratada como tema exclusivo da Defesa Civil, sem integração às políticas de ordenamento territorial, saúde, educação, meio ambiente e infraestrutura. Os órgãos que efetivamente produzem ou reproduzem riscos não incorporam a RRD em suas agendas.', '2026-02-21 12:05:31.311365+00'),
	(87, 29, 2, '2. Ausência de instâncias de diálogo: Não há espaços estruturados para que a SEDEC dialogue com os demais órgãos estaduais sobre integração de políticas públicas. A interlocução depende de relações pessoais e de demandas pontuais, sem continuidade nem institucionalidade.', '2026-02-21 12:05:31.311365+00'),
	(88, 29, 3, '3. Políticas municipais desconectadas: Os municípios produzem políticas locais sem orientação sobre como integrar a RRD de forma transversal. Sem discussão qualificada e metodologias de referência, as políticas municipais tratam a redução de riscos como tema acessório.', '2026-02-21 12:05:31.311365+00'),
	(89, 30, 1, '1. Vulnerabilidade orçamentária: Quando o Estado contingencia recursos, a Defesa Civil perde capacidade de investimento sem alternativas. Projetos estruturantes ficam restritos à disponibilidade de caixa, não à necessidade real.', '2026-02-21 12:05:31.311365+00'),
	(90, 30, 2, '2. Oportunidades perdidas: Editais de órgãos como FAPERJ, CNPq, FINEP e organismos internacionais abrem janelas de financiamento que exigem capacidade técnica de resposta rápida. Sem metodologia de monitoramento e sem banco de projetos, a Secretaria sequer toma conhecimento dessas oportunidades a tempo.', '2026-02-21 12:05:31.311365+00'),
	(91, 30, 3, '3. Ciclo de invisibilidade: Sem diversificar receitas, a Defesa Civil não gera evidências de capacidade institucional, o que reduz sua credibilidade perante financiadores — retroalimentando a dependência do Tesouro.', '2026-02-21 12:05:31.311365+00'),
	(92, 30, 4, '4. O Fundo como ponto de inflexão: O Fundo Estadual de Proteção e Defesa Civil, quando operacionalizado, representará a maior oportunidade de financiamento da história da Defesa Civil Estadual. Porém, absorver e gerir um fundo dessa natureza — com repasses fundo a fundo para municípios, controle de execução e prestação de contas em escala — exige um nível de maturidade institucional que só será alcançado se começarmos a construir agora. Chegar à operacionalização do Fundo sem a infraestrutura de gestão pronta significaria desperdiçar essa oportunidade e, pior, expor a Secretaria a riscos jurídicos e de imagem.', '2026-02-21 12:05:31.311365+00');
INSERT INTO "public"."observacoes" ("id", "acao_estrategica_id", "bloco", "conteudo", "autor_id", "autor_nome", "autor_setor", "status", "resposta_admin", "respondido_por", "respondido_em", "created_at", "updated_at") VALUES
	(1, 3, 'descricao', 'asas', 'b0b5050c-6c87-4ee5-b7d9-215defb80465', 'Karl', 'Superintendência Operacional', 'em_analise', NULL, NULL, NULL, '2026-02-21 14:26:29.86749+00', '2026-02-21 14:26:29.86749+00'),
	(12, 2, 'descricao', 'Não se aplica às demandas da redec, segundo nossa visão. Entendemos que seria tal como dispersão de foco abarcar esta atribuição estratégica.', 'afb3add1-c29a-4007-b0c2-9ee90c579b9b', 'carla da silva prado cecchi de azevedo', 'Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-02-26 11:06:02.74349+00', '2026-02-26 11:06:02.74349+00'),
	(13, 1, 'descricao', 'Aplicável à redec.', 'afb3add1-c29a-4007-b0c2-9ee90c579b9b', 'carla da silva prado cecchi de azevedo', 'Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-02-26 11:07:33.371648+00', '2026-02-26 11:07:33.371648+00'),
	(14, 1, 'ancoragem', 'Acreditamos q as redecs podem colaborar em conjuntos com órgãos apoiadores, mais precisamente na coleta de informação. Mas não possuem capacidade técnica/operacional de, sozinhos, desenvolverem modelos.', 'afb3add1-c29a-4007-b0c2-9ee90c579b9b', 'carla da silva prado cecchi de azevedo', 'Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-02-26 11:10:49.203563+00', '2026-02-26 11:10:49.203563+00'),
	(15, 1, 'destaque', 'Excelente fluxo colaborativo para desenvolvimento prático da proposta.', 'afb3add1-c29a-4007-b0c2-9ee90c579b9b', 'carla da silva prado cecchi de azevedo', 'Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-02-26 11:11:55.440338+00', '2026-02-26 11:11:55.440338+00'),
	(16, 10, 'destaque', 'Sugiro incluir o fomento à capacitação nos programas da plataforma Escola Virtual de Governo. São programas de excelência, de fácil acesso e rápida inicialização.', 'afb3add1-c29a-4007-b0c2-9ee90c579b9b', 'carla da silva prado cecchi de azevedo', 'Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-02-26 13:19:57.605627+00', '2026-02-26 13:19:57.605627+00'),
	(17, 15, 'panoramico', 'Redecs serão fonte de demanda, podendo fazer "pesquisa de campo" nos municípios, avaliando as lacunas técnicas que a sedec poderia "suprir", em certa medida, com os estudantes(quadro técnico), ainda que sazonalmente e, principalmente, no mapeamento/diagnose das áreas de risco.', 'afb3add1-c29a-4007-b0c2-9ee90c579b9b', 'carla da silva prado cecchi de azevedo', 'Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-02-26 13:30:16.200509+00', '2026-02-26 13:30:16.200509+00'),
	(18, 18, 'destaque', 'Muito importante dar retorno aos municípios e mostrar, efetivamente, que trabalhamos os dados coletados em favor deles e de suas demandas.', 'afb3add1-c29a-4007-b0c2-9ee90c579b9b', 'carla da silva prado cecchi de azevedo', 'Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-02-26 13:36:47.511501+00', '2026-02-26 13:36:47.511501+00'),
	(2, 25, 'panoramico', 'Incluir a Rede Salvar dentro desta ação estratégica, uma vez que as organizações da sociedade civil atuam também na perspectiva da prevenção de riscos.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:20:09.226318+00', '2026-02-26 19:40:33.87841+00'),
	(3, 30, 'panoramico', 'Incluir a Rede Salvar, uma vez que atua diretamente no território e em conjunto às políticas públicas intersetoriais.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:21:50.233305+00', '2026-02-26 19:40:33.87841+00'),
	(4, 1, 'panoramico', 'Incluir Rede Salvar, uma vez que atua também na prevenção de riscos e desastres nos territórios.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:23:31.460867+00', '2026-02-26 19:40:33.87841+00'),
	(5, 8, 'panoramico', 'Não sei se compete incluir a Rede Salvar, uma vez que temos um Termo de Cooperação Técnica com as agências em andamento para formalização é isso inclui a gestão documental dos processos das organizações da sociedade civil.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:25:30.628737+00', '2026-02-26 19:40:33.87841+00'),
	(6, 10, 'panoramico', 'Incluir a Rede Salvar no programa de capacitações para pontos focais da Rede de Voluntariado Estadual em Defesa Civil. Um curso específico para integrantes da sociedade civil, pertencentes a Rede Salvar, preparando-os para atuação junto à políticas sociais intersetoriais e o papel do voluntariado.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:31:22.170739+00', '2026-02-26 19:40:33.87841+00'),
	(7, 12, 'panoramico', 'Reaver atual sistema de cadastro e manutenção de dados da Rede Salvar, a fim de que seja funcional e prático aos integrantes da Rede.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:32:56.295195+00', '2026-02-26 19:40:33.87841+00'),
	(9, 20, 'panoramico', 'Incluir a Rede Salvar, reunindo todo o histórico, a trajetória de atuação e de inserção da Rede de Voluntários em Defesa Civil Estadual.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:36:08.262436+00', '2026-02-26 19:40:33.87841+00'),
	(8, 18, 'panoramico', 'Incluir a Rede Salvar no que tange a experiências exitosas junto às agências da sociedade civil nas diferentes fases do desastre e nos diferentes territórios do estado do RJ.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:34:47.625683+00', '2026-02-26 19:40:33.87841+00'),
	(10, 22, 'panoramico', 'Incluir a Rede Salvar no que tange a produção de materiais técnicos, como a produção de relatórios que registrem e deem visibilidade ao trabalho da Rede de Voluntariado.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:37:41.316443+00', '2026-02-26 19:40:33.87841+00'),
	(11, 26, 'panoramico', 'Incluir a Rede Salvar no que tange a atuação do voluntariado estadual na resposta aos possíveis desastres.', '113e7c05-7496-4c7e-b090-a599abc8c568', 'Aline Possa Silva Anjos', 'Rede Salvar', 'em_analise', NULL, NULL, NULL, '2026-02-24 14:39:08.939466+00', '2026-02-26 19:40:33.87841+00'),
	(19, 27, 'fichas', 'Incluir para REDEC: com base na 12608, "VIII - apoiar, sempre que necessário, os Municípios no levantamento das áreas de risco, na elaboração dos Planos de Contingência de Proteção e Defesa Civil e na divulgação de protocolos de prevenção e alerta e de ações emergenciais." ASSESSORIA TÉCNICA NA ELABORAÇÃO E REVISÃO DOS PLANCONS', 'f7257308-2edb-464d-b717-e6f4d21cfc60', 'Tunay Ramon Araujo Kitazawa ', 'Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-03-02 17:28:15.104764+00', '2026-03-02 17:28:15.104764+00'),
	(20, 28, 'fichas', 'Solicito esclarecimentos sobre :Apoiar a "Coordenadoria de Engenharia no acesso ao território para avaliações técnicas" - equipe especializada da SEDEC-RJ?', 'afeed092-a24e-4300-95fb-d02b78c88cad', 'FRANCISCO ALBERTO MOREIRA DA SILVA', 'Diretoria de Regionais de Defesa Civil', 'em_analise', NULL, NULL, NULL, '2026-03-02 17:36:52.83922+00', '2026-03-02 17:36:52.83922+00'),
	(21, 26, 'descricao', 'As ações de produção e atualização dos conteúdos supracitados deveriam ser realizadas por meio de GT, sendo coordenadas pelo CESTAD. Tendo em vista a escassez de militares no setor.', 'af9735ec-c165-482f-bb57-dc1a1880258f', 'Marcelo Abreu', 'Centro Estadual de Apoio a Desastres', 'em_analise', NULL, NULL, NULL, '2026-03-05 13:34:31.663433+00', '2026-03-05 13:34:31.663433+00'),
	(22, 27, 'descricao', 'Importante destacar que o CESTAD coordena as ações, porém assessoria técnica referente a assuntos específicos (decretação e S2ID, por exemplo) dependem do suporte de profissionais especializados que geralmente estão lotados em outros setores. O alinhamento institucional é vital para alcançar o objetivo.', 'af9735ec-c165-482f-bb57-dc1a1880258f', 'Marcelo Abreu', 'Centro Estadual de Apoio a Desastres', 'em_analise', NULL, NULL, NULL, '2026-03-05 13:50:27.96152+00', '2026-03-05 13:50:27.96152+00'),
	(23, 27, 'destaque', 'No item "frentes de ação" no que tange a Capacitação em resposta, vale ressaltar a  integração com as REDECs, que são fundamentais e já atuam em conjunto.', 'af9735ec-c165-482f-bb57-dc1a1880258f', 'Marcelo Abreu', 'Centro Estadual de Apoio a Desastres', 'em_analise', NULL, NULL, NULL, '2026-03-05 13:57:21.378659+00', '2026-03-05 13:57:21.378659+00'),
	(24, 24, 'descricao', 'A articulação política seria uma estratégia de alinhamento à nível de gestão de comando geral (SEDEC/SUBSEDEC), enquanto a  DGDEC atuaria à nível operacional juntamente com demais setores afins.', 'af9735ec-c165-482f-bb57-dc1a1880258f', 'Marcelo Abreu', 'Centro Estadual de Apoio a Desastres', 'em_analise', NULL, NULL, NULL, '2026-03-05 14:27:33.877129+00', '2026-03-05 14:27:33.877129+00'),
	(25, 27, 'descricao', 'Reforçando a informação referente ao CESTAD, a equipe da DGDEC também não possui equipe de suporte com profissionais especializados no que tange a parte jurídica, por exemplo, necessitando de articulação com outros setores. Quanto ao suporte operacional direto e complementar, a DGDEC compreende como sua atribuição legal.', 'af9735ec-c165-482f-bb57-dc1a1880258f', 'Marcelo Abreu', 'Centro Estadual de Apoio a Desastres', 'em_analise', NULL, NULL, NULL, '2026-03-05 16:20:32.388121+00', '2026-03-05 16:20:32.388121+00'),
	(26, 28, 'destaque', 'no item fluxo da ação, não ficou claro a integração da coordenadoria de Engenharia com a DGDEC.', 'af9735ec-c165-482f-bb57-dc1a1880258f', 'Marcelo Abreu', 'Centro Estadual de Apoio a Desastres', 'em_analise', NULL, NULL, NULL, '2026-03-05 16:39:07.419164+00', '2026-03-05 16:39:07.419164+00'),
	(27, 26, 'panoramico', 'Incluir o CESTGEN no que se refere ao gerenciamento de emergência nuclear, à nível estadual, como também, sendo responsável pela implementação do Plano de Emergência Externo do Estado do Rio de Janeiro.', 'dfee39fc-f3af-451d-aaca-c163c06ac3d4', 'Giovanni Mouta Giglio', 'Órgãos Subordinados (Direções, Coordenações, REDECs e demais setores)', 'em_analise', NULL, NULL, NULL, '2026-03-05 21:06:13.276159+00', '2026-03-05 21:06:13.276159+00'),
	(28, 26, 'descricao', 'No caso da emergência nuclear, as doutrinas de preparação e resposta, contidas no Plano de Emergência Externo do Estado do RJ, são construídas a partir de grupos de trabalhos incluindo a própria SEDEC RJ e steakholders externos a sua estrutura', 'dfee39fc-f3af-451d-aaca-c163c06ac3d4', 'Giovanni Mouta Giglio', 'Órgãos Subordinados (Direções, Coordenações, REDECs e demais setores)', 'em_analise', NULL, NULL, NULL, '2026-03-05 21:10:15.969131+00', '2026-03-05 21:10:15.969131+00'),
	(29, 27, 'descricao', 'O CESTGEN além de realizar o gerenciamento da emergência nuclear à nível estadual, fornece aos munícipios, que possuem instalações de natureza nuclear, apoio técnico, a partir de sua área de influência no Estado. Representantes de instituições públicas e privadas, de nível estadual e federal, fazem parte de uma rede com proficiências específicas, a fim de auxiliar na solução da emergência.', 'dfee39fc-f3af-451d-aaca-c163c06ac3d4', 'Giovanni Mouta Giglio', 'Órgãos Subordinados (Direções, Coordenações, REDECs e demais setores)', 'em_analise', NULL, NULL, NULL, '2026-03-05 21:27:51.048843+00', '2026-03-05 21:27:51.048843+00'),
	(30, 27, 'destaque', 'O CESTGEN possui seu GRAC específico em caso de emergência de natureza nuclear.', 'dfee39fc-f3af-451d-aaca-c163c06ac3d4', 'Giovanni Mouta Giglio', 'Órgãos Subordinados (Direções, Coordenações, REDECs e demais setores)', 'em_analise', NULL, NULL, NULL, '2026-03-05 21:28:56.820587+00', '2026-03-05 21:28:56.820587+00'),
	(31, 27, 'fichas', 'Incluir o CESTGEN considerando que possui a missão de implementar o Plano de emergência externo (PEE/RJ); prestar assessoria para decisão do Governo Estadual, na ocorrência de uma situação de emergência; coordenar o apoio dos órgãos públicos e privados sediados em sua área de influência para complementar as ações empreendidas e os meios utilizados na resposta a uma situação de emergência nuclear.', 'dfee39fc-f3af-451d-aaca-c163c06ac3d4', 'Giovanni Mouta Giglio', 'Órgãos Subordinados (Direções, Coordenações, REDECs e demais setores)', 'em_analise', NULL, NULL, NULL, '2026-03-05 21:30:49.840927+00', '2026-03-05 21:30:49.840927+00');
INSERT INTO "public"."panoramico_linhas" ("id", "acao_estrategica_id", "ordem", "setor_display", "papel", "sintese_contribuicao", "nao_faz", "created_at") VALUES
	(1, 1, 1, 'DGAC', 'Líder da Ação', 'Cria, analisa, sistematiza e modela projetos-prateleira de proteção comunitária', 'Não coleta práticas nos municípios; não capacita formalmente', '2026-02-21 12:05:31.311365+00'),
	(2, 1, 2, 'ICTDEC (com CEPEDEC)', 'Suporte Científico sob Demanda', 'Fornece rigor científico e metodologias estatísticas quando solicitado pela DGAC', 'Não lidera criação ou sistematização; não modela projetos', '2026-02-21 12:05:31.311365+00'),
	(3, 1, 3, 'ESDEC', 'Capacitadora', 'Forma agentes municipais para implementação dos projetos do portfólio', 'Não modela projetos; não coleta práticas', '2026-02-21 12:05:31.311365+00'),
	(4, 1, 4, 'REDECs (via DREDEC)', 'Coleta e Difusão', 'Colhe práticas nos municípios; disponibiliza portfólio; articula adesão', 'Não modela projetos; não sistematiza metodologicamente', '2026-02-21 12:05:31.311365+00'),
	(5, 1, 5, 'SUOP (sob aval da SUBSEGOP)', 'Validação e Coordenação', 'Valida alinhamento estratégico; coordena integração entre órgãos', 'Não produz conteúdo; não executa na ponta', '2026-02-21 12:05:31.311365+00'),
	(6, 2, 1, 'SUOP (sob aval da SUBSEGOP)', 'Líder Coordenador Transversal', 'Define prioridades de captação; valida propostas; articula setores; destrava gargalos', 'Não elabora projetos; não executa captação isoladamente', '2026-02-21 12:05:31.311365+00'),
	(7, 2, 2, 'Gabinete de Gestão de Projetos', 'Coexecutor de Gestão de Portfólio', 'Gere o ciclo de vida dos projetos captados; monitora execução; consolida portfólio', 'Não elabora projetos técnicos; não substitui a SUOP na priorização', '2026-02-21 12:05:31.311365+00'),
	(8, 2, 3, 'ICTDEC', 'Coexecutor Técnico-Metodológico', 'Elabora metodologia de monitoramento; capta recursos de P&D; assessora elaboração técnica', 'Não negocia politicamente; não capta fora de P&D sem diretriz', '2026-02-21 12:05:31.311365+00'),
	(9, 2, 4, 'SUBSEGAD', 'Coexecutor Financeiro', 'Governança financeira; conformidade contábil; modelagem de fundos', 'Não bloqueia por formalismo; não prioriza', '2026-02-21 12:05:31.311365+00'),
	(10, 2, 5, 'ASSEJUR', 'Assessoria Jurídica', 'Segurança jurídica dos instrumentos; parecer sobre convênios e repasses', 'Não decide mérito técnico ou prioridade estratégica', '2026-02-21 12:05:31.311365+00'),
	(11, 2, 6, 'Órgãos Finalísticos', 'Provedores de Demanda e Executores', 'Identificam necessidades; participam da construção; executam e prestam contas', 'Não solicitam sem projeto; não fragmentam demandas', '2026-02-21 12:05:31.311365+00'),
	(12, 3, 1, 'Alta Gestão (SUBSEGOP / Secretário)', 'Líder Institucional', 'Chancela política; valida indicadores; conduz análises críticas; cobra entregas', 'Não elabora metodologia; não consolida dados', '2026-02-21 12:05:31.311365+00'),
	(13, 3, 2, 'ICTDEC (DAEAD)', 'Executor Central Técnico-Metodológico', 'Elabora metodologia; define indicadores; consolida dados; produz relatórios; conduz reuniões de monitoramento', 'Não decide prioridades políticas; não executa ações dos setores', '2026-02-21 12:05:31.311365+00'),
	(14, 3, 3, 'SUOP (sob aval da SUBSEGOP)', 'Articulador Operacional', 'Garante aderência dos órgãos; intermedia entre ICTDEC e subordinados; destrava participação', 'Não elabora indicadores; não produz relatórios', '2026-02-21 12:05:31.311365+00'),
	(15, 3, 4, 'Órgãos Subordinados', 'Alimentadores e Executores', 'Reportam indicadores; participam das análises críticas; executam correções de rota', 'Não definem indicadores globais; não alteram prioridades', '2026-02-21 12:05:31.311365+00'),
