	(101, 27, 1, 'SUOP', 'Coordenador da Ação', 'Coordena atuação multiórgãos; prioriza municípios; articula recursos', 'Não executa na ponta; não define protocolos técnicos', '2026-02-21 12:05:31.311365+00'),
	(102, 27, 2, 'DGDEC', 'Resposta e Assistência Humanitária', 'Mobiliza suporte operacional; assessora planos de contingência; coordena logística de resposta', 'Não monitora riscos; não capacita formalmente', '2026-02-21 12:05:31.311365+00'),
	(103, 27, 3, 'CESTAD', 'Coordenação de Resposta', 'Coordena ações de resposta; opera estruturas de gestão de crises', 'Não presta assistência humanitária; não capacita', '2026-02-21 12:05:31.311365+00'),
	(104, 27, 4, 'CEMADEN-RJ', 'Alertas e Suporte em Crise', 'Fornece alertas geohidrometeorológicos e panoramas de risco para preparação e resposta', 'Não coordena resposta; não mobiliza logística', '2026-02-21 12:05:31.311365+00'),
	(105, 27, 5, 'GRAC', 'Integração Multisetorial', 'Articula órgãos estaduais e entidades para atuação coordenada em desastres', 'Não executa ações operacionais diretas', '2026-02-21 12:05:31.311365+00'),
	(106, 27, 6, 'ESDEC', 'Capacitadora', 'Forma agentes municipais em preparação e resposta a desastres', 'Não executa resposta; não assessora planos', '2026-02-21 12:05:31.311365+00'),
	(107, 27, 7, 'REDECs (via DREDEC)', 'Executoras na Ponta', 'Operacionalizam a colaboração no território; apoiam simulações e resposta', 'Não definem protocolos; não formalizam compromissos', '2026-02-21 12:05:31.311365+00'),
	(108, 28, 1, 'SUOP', 'Líder da Ação', 'Define critérios de priorização; coordena o fluxo de demandas; monitora execução', 'Não executa recuperação; não articula diretamente com órgãos externos', '2026-02-21 12:05:31.311365+00'),
	(109, 28, 2, 'GRAC', 'Articulador com Órgãos Setoriais', 'Mobiliza órgãos estaduais competentes para execução dos projetos de recuperação', 'Não avalia danos; não prioriza demandas', '2026-02-21 12:05:31.311365+00'),
	(110, 28, 3, 'DGDEC', 'Canal com Municípios e Consolidação de Danos', 'Recebe demandas; consolida avaliações de danos; reporta à SUOP', 'Não prioriza; não articula com órgãos externos', '2026-02-21 12:05:31.311365+00'),
	(111, 28, 4, 'Coord. Engenharia', 'Avaliação Técnica de Infraestrutura', 'Avalia danos em infraestrutura; emite pareceres técnicos', 'Não executa obras; não consolida danos gerais', '2026-02-21 12:05:31.311365+00'),
	(112, 28, 5, 'REDECs (via DREDEC)', 'Levantamento na Ponta', 'Realiza levantamento de danos no território; reporta necessidades municipais', 'Não avalia infraestrutura tecnicamente; não prioriza', '2026-02-21 12:05:31.311365+00'),
	(113, 29, 1, 'ICTDEC (com CEPEDEC)', 'Líder da Produção de Diretrizes', 'Produz diretrizes de reconstrução resiliente; estrutura conteúdo para difusão', 'Não articula politicamente com órgãos externos', '2026-02-21 12:05:31.311365+00'),
	(114, 29, 2, 'Coord. Engenharia', 'Conteúdo Técnico de Engenharia', 'Fornece conteúdo técnico sobre engenharia resiliente aplicável à recuperação', 'Não produz diretrizes conceituais; não difunde', '2026-02-21 12:05:31.311365+00'),
	(115, 29, 3, 'SUOP (sob aval da SUBSEGOP)', 'Validação e Coordenação', 'Valida alinhamento estratégico; coordena execução interna', 'Não produz conteúdo; não articula com órgãos externos', '2026-02-21 12:05:31.311365+00'),
	(116, 29, 4, 'SUBSEGOP', 'Articulação Político-Institucional', 'Articula acesso aos órgãos estaduais executores para difusão das diretrizes', 'Não produz conteúdo técnico; não executa capacitação', '2026-02-21 12:05:31.311365+00'),
	(117, 30, 1, 'SUBSEGOP', 'Líder da Articulação Político-Institucional', 'Conduz o diálogo com órgãos estaduais e atores externos; viabiliza instâncias de discussão', 'Não produz conteúdo técnico; não capacita', '2026-02-21 12:05:31.311365+00'),
	(118, 30, 2, 'ICTDEC (com CEPEDEC)', 'Conteúdo Técnico e Metodológico', 'Produz estudos, metodologias e subsídios para qualificar as discussões', 'Não articula politicamente com órgãos externos', '2026-02-21 12:05:31.311365+00'),
	(119, 30, 3, 'SUOP', 'Coordenação Interna', 'Coordena a participação dos órgãos da SEDEC; valida alinhamento estratégico', 'Não articula com órgãos externos; não produz conteúdo', '2026-02-21 12:05:31.311365+00'),
	(120, 30, 4, 'ESDEC', 'Capacitadora', 'Forma agentes para produção de políticas transversais de RRD', 'Não articula com órgãos externos; não produz diretrizes', '2026-02-21 12:05:31.311365+00'),
	(121, 30, 5, 'DGAC', 'Dimensão Comunitária', 'Contribui com percepção de risco e participação social nas discussões', 'Não articula com órgãos estaduais; não produz políticas', '2026-02-21 12:05:31.311365+00'),
	(122, 30, 6, 'CEAMA', 'Dimensão Ambiental', 'Contribui com integração de políticas ambientais e de RRD', 'Não articula com órgãos fora do tema ambiental', '2026-02-21 12:05:31.311365+00'),
	(123, 30, 7, 'REDECs (via DREDEC)', 'Participação Municipal', 'Articula participação dos municípios e traz realidades locais', 'Não produz conteúdo técnico; não articula com órgãos estaduais', '2026-02-21 12:05:31.311365+00'),
	(124, 30, 8, 'CONEPDEC', 'Instância Consultiva e Propositiva', 'Valida propostas de políticas transversais; confere legitimidade multisetorial', 'Não executa ações operacionais de RRD', '2026-02-21 12:05:31.311365+00');
